final class CodexAppServerTests: XCTestCase {
    private final class AppServerExtensionRecorder:
        ExtensionThreadLifecycleContributor,
        ExtensionTurnLifecycleContributor,
        ExtensionConfigContributor,
        ExtensionTokenUsageContributor,
        ExtensionContextContributor,
        ExtensionToolContributor,
        ExtensionApprovalReviewContributor,
        ExtensionTurnItemContributor,
        @unchecked Sendable
    {
        private let lock = NSLock()
        private var values: [String] = []

        var records: [String] {
            lock.withLock { values }
        }

        func onThreadStart(_ input: ExtensionThreadStartInput) {
            input.threadStore.insert("thread-started")
            append("thread-start:\(input.threadID):\(input.config.model ?? "nil")")
        }

        func onThreadResume(_ input: ExtensionThreadResumeInput) {
            append("thread-resume:\(input.threadID):\(input.threadStore.get(String.self) ?? "missing")")
        }

        func onThreadStop(_ input: ExtensionThreadStopInput) {
            append("thread-stop:\(input.threadID):\(input.threadStore.get(String.self) ?? "missing")")
        }

        func onTurnStart(_ input: ExtensionTurnStartInput) {
            input.turnStore.insert("turn-started")
            append("turn-start:\(input.turnID):\(input.threadStore.get(String.self) ?? "missing")")
        }

        func onTurnStop(_ input: ExtensionTurnStopInput) {
            append("turn-stop:\(input.turnID):\(input.turnStore.get(String.self) ?? "missing")")
        }

        func onTurnAbort(_ input: ExtensionTurnAbortInput) {
            append("turn-abort:\(input.turnID):\(input.reason.rawValue)")
        }

        func onConfigChanged(_ input: ExtensionConfigChangedInput) {
            append("config-changed:\(input.previousConfig.model ?? "nil")->\(input.newConfig.model ?? "nil")")
        }

        func onTokenUsage(
            sessionStore: ExtensionData,
            threadStore: ExtensionData,
            turnStore: ExtensionData,
            threadID: ThreadId,
            turnID: String,
            tokenUsage: TokenUsageInfo
        ) {
            append("tokens:\(turnID):\(tokenUsage.totalTokenUsage.totalTokens):\(turnStore.get(String.self) ?? "missing")")
        }

        func contribute(
            sessionStore: ExtensionData,
            threadStore: ExtensionData
        ) async -> [ExtensionPromptFragment] {
            [
                .developerPolicy("live-prompt:\(threadStore.get(String.self) ?? "missing")")
            ]
        }

        func tools(sessionStore: ExtensionData, threadStore: ExtensionData) -> [ExtensionTool] {
            [
                ExtensionTool(
                    spec: .function(ResponsesAPITool(
                        name: "extension/live_tool",
                        description: "Live tool sees \(threadStore.get(String.self) ?? "missing")",
                        parameters: .object(
                            properties: [:],
                            required: [],
                            additionalProperties: .boolean(false)
                        )
                    )),
                    supportsParallelToolCalls: true,
                    executor: { _ in JSONToolOutput(.string("ok")) }
                )
            ]
        }

        func contribute(
            sessionStore: ExtensionData,
            threadStore: ExtensionData,
            prompt: String
        ) async -> ReviewDecision? {
            guard threadStore.get(String.self) == "thread-started",
                  prompt.contains("claim")
            else {
                return nil
            }
            return .approvedForSession
        }

        func contribute(
            threadStore: ExtensionData,
            turnStore: ExtensionData,
            item: TurnItem
        ) async throws -> TurnItem {
            append("turn-item:\(threadStore.get(String.self) ?? "missing"):\(turnStore.get(String.self) ?? "missing")")
            guard case let .agentMessage(agentMessage) = item else {
                return item
            }
            return .agentMessage(AgentMessageItem(
                id: agentMessage.id,
                content: [
                    .text("contributed:\(threadStore.get(String.self) ?? "missing"):\(turnStore.get(String.self) ?? "missing")")
                ],
                phase: agentMessage.phase,
                memoryCitation: agentMessage.memoryCitation
            ))
        }

        private func append(_ value: String) {
            lock.withLock {
                values.append(value)
            }
        }
    }

