    func testAppServerWebSocketTransportRoutesInitializeLikeRust() async throws {
        let temp = try TemporaryDirectory()
        let transport = AppServerWebSocketTransport(configuration: testConfiguration(codexHome: temp.url))
        let (stream, continuation) = AsyncStream.makeStream(of: String.self)
        let serverTask = Task.detached {
            try await transport.run(host: "127.0.0.1", port: 0) { url in
                continuation.yield(url.trimmingCharacters(in: .whitespacesAndNewlines))
            }
        }
        defer {
            serverTask.cancel()
        }

        var iterator = stream.makeAsyncIterator()
        let announcedURL = await iterator.next()
        let urlString = try XCTUnwrap(announcedURL)
        XCTAssertTrue(urlString.hasPrefix("ws://127.0.0.1:"))

        let webSocket = URLSession.shared.webSocketTask(with: try XCTUnwrap(URL(string: urlString)))
        webSocket.resume()
        defer {
            webSocket.cancel(with: .goingAway, reason: nil)
        }

        try await webSocket.send(.string(#"{"id":1,"method":"initialize","params":{"clientInfo":{"name":"test","version":"0"},"capabilities":{"experimentalApi":true}}}"#))
        let response = try decode(Data((try await receiveWebSocketText(webSocket)).utf8))
        XCTAssertEqual(response["id"] as? Int, 1)
        let result = try XCTUnwrap(response["result"] as? [String: Any])
        XCTAssertEqual(result["codexHome"] as? String, temp.url.standardizedFileURL.path)
        XCTAssertEqual(result["platformFamily"] as? String, "unix")
    }

    func testRemoteControlAppServerBridgeRoutesVirtualConnectionRequestsLikeRust() async throws {
        let temp = try TemporaryDirectory()
        let clientID = RemoteControlClientID("client-1")
        let streamID = RemoteControlStreamID("stream-1")
        let connectionID = RemoteControlVirtualConnectionID(1)
        let initialize = ExecServerJSONRPCMessage.request(ExecServerJSONRPCRequest(
            id: .integer(1),
            method: "initialize",
            params: .object([
                "clientInfo": .object([
                    "name": .string("test"),
                    "version": .string("0")
                ]),
                "capabilities": .object([
                    "experimentalApi": .bool(true)
                ])
            ])
        ))
        var transport = RemoteControlVirtualTransportCore()
        var bridge = RemoteControlAppServerBridge(configuration: testConfiguration(codexHome: temp.url))

        let transportStep = transport.handleClientEnvelope(RemoteControlClientEnvelope(
            event: .clientMessage(message: initialize),
            clientID: clientID,
            streamID: streamID,
            seqID: 1,
            cursor: nil
        ), now: 10)
        XCTAssertEqual(transportStep.transportEvents, [
            .connectionOpened(connectionID: connectionID, clientID: clientID, streamID: streamID),
            .incomingMessage(connectionID: connectionID, message: initialize)
        ])

        let bridgeStep = await bridge.handle(transportStep.transportEvents)
        XCTAssertEqual(bridgeStep.droppedUnknownConnectionIDs, [])
        let initializeResponse = try response(with: .integer(1), in: bridgeStep.outgoingMessages)
        guard case let .object(result) = initializeResponse.result else {
            return XCTFail("initialize response did not include an object result")
        }
        XCTAssertEqual(result["codexHome"], .string(temp.url.standardizedFileURL.path))
        XCTAssertEqual(result["platformFamily"], .string("unix"))

        let queued = try XCTUnwrap(transport.enqueueOutgoingMessage(
            connectionID: connectionID,
            message: .response(initializeResponse)
        ))
        XCTAssertEqual(
            queued,
            RemoteControlQueuedServerEnvelope(
                event: .serverMessage(message: .response(initializeResponse)),
                clientID: clientID,
                streamID: streamID
            )
        )
    }

    func testRemoteControlAppServerVirtualLoopQueuesServerEventsLikeRust() async throws {
        let temp = try TemporaryDirectory()
        let clientID = RemoteControlClientID("client-1")
        let streamID = RemoteControlStreamID("stream-1")
        let connectionID = RemoteControlVirtualConnectionID(1)
        let initialize = ExecServerJSONRPCMessage.request(ExecServerJSONRPCRequest(
            id: .integer(1),
            method: "initialize",
            params: .object([
                "clientInfo": .object([
                    "name": .string("test"),
                    "version": .string("0")
                ]),
                "capabilities": .object([
                    "experimentalApi": .bool(true)
                ])
            ])
        ))
        var loop = RemoteControlAppServerVirtualLoop(configuration: testConfiguration(codexHome: temp.url))

        let initializeStep = await loop.handleClientEnvelope(RemoteControlClientEnvelope(
            event: .clientMessage(message: initialize),
            clientID: clientID,
            streamID: streamID,
            seqID: 1,
            cursor: nil
        ), now: 10)

        XCTAssertEqual(initializeStep.transportStep.transportEvents, [
            .connectionOpened(connectionID: connectionID, clientID: clientID, streamID: streamID),
            .incomingMessage(connectionID: connectionID, message: initialize)
        ])
        XCTAssertEqual(initializeStep.bridgeStep.droppedUnknownConnectionIDs, [])
        let initializeResponse = try response(with: .integer(1), in: initializeStep.serverEvents)
        guard case let .object(result) = initializeResponse.result else {
            return XCTFail("initialize response did not include an object result")
        }
        XCTAssertEqual(result["codexHome"], .string(temp.url.standardizedFileURL.path))
        XCTAssertEqual(result["platformFamily"], .string("unix"))
        XCTAssertEqual(initializeStep.serverEvents.map(\.clientID), [clientID])
        XCTAssertEqual(initializeStep.serverEvents.map(\.streamID), [streamID])

        let pingStep = await loop.handleClientEnvelope(RemoteControlClientEnvelope(
            event: .ping,
            clientID: clientID,
            streamID: streamID,
            seqID: nil,
            cursor: nil
        ), now: 11)
        XCTAssertEqual(pingStep.transportStep.transportEvents, [])
        XCTAssertEqual(pingStep.bridgeStep, RemoteControlAppServerBridgeStep())
        XCTAssertEqual(pingStep.serverEvents, [
            RemoteControlQueuedServerEnvelope(
                event: .pong(status: .active),
                clientID: clientID,
                streamID: streamID
            )
        ])
    }

    func testRemoteControlAppServerVirtualLoopClosesConnectionsLikeRust() async throws {
        let temp = try TemporaryDirectory()
        let clientID = RemoteControlClientID("client-1")
        let streamID = RemoteControlStreamID("stream-1")
        let connectionID = RemoteControlVirtualConnectionID(1)
        let initialize = ExecServerJSONRPCMessage.request(ExecServerJSONRPCRequest(
            id: .integer(1),
            method: "initialize",
            params: .object([
                "clientInfo": .object([
                    "name": .string("test"),
                    "version": .string("0")
                ])
            ])
        ))
        let initialized = ExecServerJSONRPCMessage.notification(ExecServerJSONRPCNotification(method: "initialized"))
        var loop = RemoteControlAppServerVirtualLoop(configuration: testConfiguration(codexHome: temp.url))

        _ = await loop.handleClientEnvelope(RemoteControlClientEnvelope(
            event: .clientMessage(message: initialize),
            clientID: clientID,
            streamID: streamID,
            seqID: 1,
            cursor: nil
        ), now: 10)
        let closeStep = await loop.handleClientEnvelope(RemoteControlClientEnvelope(
            event: .clientClosed,
            clientID: clientID,
            streamID: streamID,
            seqID: 2,
            cursor: nil
        ), now: 11)
        XCTAssertEqual(closeStep.transportStep.transportEvents, [
            .connectionClosed(connectionID: connectionID)
        ])
        XCTAssertEqual(closeStep.serverEvents, [])

        let afterCloseStep = await loop.handleClientEnvelope(RemoteControlClientEnvelope(
            event: .clientMessage(message: initialized),
            clientID: clientID,
            streamID: streamID,
            seqID: 3,
            cursor: nil
        ), now: 12)
        XCTAssertEqual(afterCloseStep.transportStep, RemoteControlVirtualTransportStep())
        XCTAssertEqual(afterCloseStep.bridgeStep, RemoteControlAppServerBridgeStep())
        XCTAssertEqual(afterCloseStep.serverEvents, [])

        let pingStep = await loop.handleClientEnvelope(RemoteControlClientEnvelope(
            event: .ping,
            clientID: clientID,
            streamID: streamID,
            seqID: nil,
            cursor: nil
        ), now: 13)
        XCTAssertEqual(pingStep.serverEvents, [
            RemoteControlQueuedServerEnvelope(
                event: .pong(status: .unknown),
                clientID: clientID,
                streamID: streamID
            )
        ])
    }

    func testRemoteControlAppServerWebSocketSessionRoutesFramesThroughAppServerLikeRust() async throws {
        let temp = try TemporaryDirectory()
        let clientID = RemoteControlClientID("client-1")
        let streamID = RemoteControlStreamID("stream-1")
        let initialize = ExecServerJSONRPCMessage.request(ExecServerJSONRPCRequest(
            id: .integer(1),
            method: "initialize",
            params: .object([
                "clientInfo": .object([
                    "name": .string("test"),
                    "version": .string("0")
                ]),
                "capabilities": .object([
                    "experimentalApi": .bool(true)
                ])
            ])
        ))
        let transport = RemoteControlAppServerRecordingWebSocketTransport(incoming: [
            .text(try remoteControlEnvelopeText(RemoteControlClientEnvelope(
                event: .clientMessage(message: initialize),
                clientID: clientID,
                streamID: streamID,
                seqID: 1,
                cursor: nil
            ))),
            .text(try remoteControlEnvelopeText(RemoteControlClientEnvelope(
                event: .ping,
                clientID: clientID,
                streamID: streamID,
                seqID: nil,
                cursor: nil
            )))
        ])
        var session = RemoteControlAppServerWebSocketSession(
            transport: transport,
            statusPublisher: RemoteControlStatusPublisherCore(snapshot: RemoteControlStatusSnapshot(
                status: .connected,
                installationID: "install-1",
                environmentID: "env-1"
            )),
            configuration: testConfiguration(codexHome: temp.url)
        )

        let initializeStep = try await session.receive(now: 10)
        XCTAssertEqual(initializeStep.connectionStep.trackerEffects.count, 2)
        XCTAssertEqual(initializeStep.appServerStep.transportStep.transportEvents.count, 2)
        XCTAssertEqual(initializeStep.writerSteps.count, 1)
        let initializeFrames = await transport.sentFrames()
        XCTAssertEqual(initializeFrames.count, 1)
        let initializeEnvelope = try remoteControlServerEnvelope(from: try XCTUnwrap(initializeFrames.first))
        XCTAssertEqual(initializeEnvelope.clientID, clientID)
        XCTAssertEqual(initializeEnvelope.streamID, streamID)
        XCTAssertEqual(initializeEnvelope.seqID, 1)
        guard case let .serverMessage(.response(initializeResponse)) = initializeEnvelope.event,
              case let .object(result) = initializeResponse.result
        else {
            return XCTFail("initialize response was not forwarded as a remote-control server event")
        }
        XCTAssertEqual(initializeResponse.id, .integer(1))
        XCTAssertEqual(result["codexHome"], .string(temp.url.standardizedFileURL.path))
        XCTAssertEqual(result["platformFamily"], .string("unix"))

        let pingStep = try await session.receive(now: 11)
        XCTAssertEqual(pingStep.appServerStep.transportStep.transportEvents, [])
        XCTAssertEqual(pingStep.appServerStep.serverEvents, [
            RemoteControlQueuedServerEnvelope(
                event: .pong(status: .active),
                clientID: clientID,
                streamID: streamID
            )
        ])
        let pingFrames = await transport.sentFrames()
        XCTAssertEqual(pingFrames.count, 2)
        XCTAssertEqual(
            try remoteControlServerEnvelope(from: try XCTUnwrap(pingFrames.last)),
            RemoteControlServerEnvelope(
                event: .pong(status: .active),
                clientID: clientID,
                streamID: streamID,
                seqID: 2
            )
        )
    }

    func testRemoteControlAppServerWebSocketSessionRunsUntilTerminalEventLikeRust() async throws {
        let temp = try TemporaryDirectory()
        let clientID = RemoteControlClientID("client-1")
        let streamID = RemoteControlStreamID("stream-1")
        let initialize = ExecServerJSONRPCMessage.request(ExecServerJSONRPCRequest(
            id: .integer(1),
            method: "initialize",
            params: .object([
                "clientInfo": .object([
                    "name": .string("test"),
                    "version": .string("0")
                ]),
                "capabilities": .object([
                    "experimentalApi": .bool(true)
                ])
            ])
        ))
        let transport = RemoteControlAppServerRecordingWebSocketTransport(incoming: [
            .text(try remoteControlEnvelopeText(RemoteControlClientEnvelope(
                event: .clientMessage(message: initialize),
                clientID: clientID,
                streamID: streamID,
                seqID: 1,
                cursor: nil
            )))
        ])
        var session = RemoteControlAppServerWebSocketSession(
            transport: transport,
            statusPublisher: RemoteControlStatusPublisherCore(snapshot: RemoteControlStatusSnapshot(
                status: .connected,
                installationID: "install-1",
                environmentID: "env-1"
            )),
            configuration: testConfiguration(codexHome: temp.url)
        )

        let steps = try await session.runUntilTerminal(now: { 10 })

        XCTAssertEqual(steps.count, 2)
        XCTAssertEqual(steps[0].connectionStep.trackerEffects.count, 2)
        XCTAssertNil(steps[0].terminalEnd)
        XCTAssertEqual(steps[1].terminalEnd, .reconnect("websocket stream ended"))
        let closeCount = await transport.closeCount()
        XCTAssertEqual(closeCount, 1)
        let frames = await transport.sentFrames()
        XCTAssertEqual(frames.count, 1)
        let envelope = try remoteControlServerEnvelope(from: try XCTUnwrap(frames.first))
        XCTAssertEqual(envelope.clientID, clientID)
        XCTAssertEqual(envelope.streamID, streamID)
        guard case let .serverMessage(.response(response)) = envelope.event else {
            return XCTFail("initialize response was not forwarded before terminal websocket EOF")
        }
        XCTAssertEqual(response.id, .integer(1))
    }

    func testRemoteControlAppServerExecutableRuntimeConnectsRunsSessionAndRecordsTerminalLikeRust() async throws {
        let temp = try TemporaryDirectory()
        let clientID = RemoteControlClientID("client-1")
        let streamID = RemoteControlStreamID("stream-1")
        let initialize = ExecServerJSONRPCMessage.request(ExecServerJSONRPCRequest(
            id: .integer(1),
            method: "initialize",
            params: .object([
                "clientInfo": .object([
                    "name": .string("test"),
                    "version": .string("0")
                ]),
                "capabilities": .object([
                    "experimentalApi": .bool(true)
                ])
            ])
        ))
        let transport = RemoteControlAppServerRecordingWebSocketTransport(incoming: [
            .text(try remoteControlEnvelopeText(RemoteControlClientEnvelope(
                event: .clientMessage(message: initialize),
                clientID: clientID,
                streamID: streamID,
                seqID: 1,
                cursor: nil
            )))
        ])
        let connectionProbe = RemoteControlAppServerExecutableConnectionProbe()
        var runtime = RemoteControlAppServerExecutableRuntime(
            runtime: try RemoteControlRuntimeCore(
                remoteControlURL: "https://chatgpt.com/backend-api",
                installationID: "install-1",
                requestedEnabled: true,
                stateDatabaseAvailable: true
            ),
            configuration: testConfiguration(codexHome: temp.url),
            connect: { target, appServerClientName in
                await connectionProbe.record(target: target, appServerClientName: appServerClientName)
                return RemoteControlAppServerExecutableConnection(
                    transport: transport,
                    environmentID: "env-1"
                )
            }
        )

        let steps = try await runtime.start(now: { 10 })

        XCTAssertEqual(steps.count, 3)
        XCTAssertEqual(steps[0].runtimeStep.action, .connect(RemoteControlTarget(
            websocketURL: "wss://chatgpt.com/backend-api/wham/remote/control/server",
            enrollURL: "https://chatgpt.com/backend-api/wham/remote/control/server/enroll"
        ), appServerClientName: nil))
        XCTAssertEqual(steps[1].runtimeStep, RemoteControlRuntimeStep(
            action: .connected,
            statusUpdates: [
                RemoteControlStatusSnapshot(
                    status: .connecting,
                    installationID: "install-1",
                    environmentID: "env-1"
                ),
                RemoteControlStatusSnapshot(
                    status: .connected,
                    installationID: "install-1",
                    environmentID: "env-1"
                ),
            ]
        ))
        XCTAssertEqual(steps[2].terminalEnd, .reconnect("websocket stream ended"))
        XCTAssertEqual(steps[2].runtimeStep.action, .reconnect(appServerClientName: nil))
        XCTAssertEqual(steps[2].sessionSteps.count, 2)

        let connections = await connectionProbe.connections()
        XCTAssertEqual(connections, [RemoteControlAppServerExecutableConnectionProbe.Connection(
            target: RemoteControlTarget(
                websocketURL: "wss://chatgpt.com/backend-api/wham/remote/control/server",
                enrollURL: "https://chatgpt.com/backend-api/wham/remote/control/server/enroll"
            ),
            appServerClientName: nil
        )])

        let frames = await transport.sentFrames()
        let envelopes = try frames.map(remoteControlServerEnvelope(from:))
        XCTAssertEqual(envelopes.count, 2)
        guard case let .serverMessage(.response(response)) = envelopes[0].event else {
            return XCTFail("initialize response was not forwarded before terminal websocket EOF")
        }
        XCTAssertEqual(response.id, .integer(1))
        guard case let .serverMessage(.notification(notification)) = envelopes[1].event,
              case let .object(params) = notification.params
        else {
            return XCTFail("connected remote-control status notification was not forwarded")
        }
        XCTAssertEqual(notification.method, "remoteControl/status/changed")
        XCTAssertEqual(params["status"], .string("connected"))
        XCTAssertEqual(params["installationId"], .string("install-1"))
        XCTAssertEqual(params["environmentId"], .string("env-1"))
    }

    func testRemoteControlAppServerExecutableRuntimePublishesStatusToLocalClientsLikeRust() async throws {
        let temp = try TemporaryDirectory()
        let notificationCapture = AppServerNotificationCapture()
        let configuration = testConfiguration(
            codexHome: temp.url,
            remoteControlStatusSnapshot: CodexAppServerConfiguration.RemoteControlStatusSnapshot(
                status: .connecting,
                installationID: "install-1",
                environmentID: nil
            )
        )
        _ = try initializedProcessor(
            configuration: configuration,
            connectionID: 99,
            notificationSink: { data in await notificationCapture.append(data) },
            experimentalAPIEnabled: true
        )
        let transport = RemoteControlAppServerRecordingWebSocketTransport(incoming: [])
        var runtime = RemoteControlAppServerExecutableRuntime(
            runtime: try RemoteControlRuntimeCore(
                remoteControlURL: "https://chatgpt.com/backend-api",
                installationID: "install-1",
                requestedEnabled: true,
                stateDatabaseAvailable: true
            ),
            configuration: configuration,
            connect: { _, _ in
                RemoteControlAppServerExecutableConnection(
                    transport: transport,
                    environmentID: "env-1"
                )
            }
        )

        _ = try await runtime.start(now: { 10 }, maxReceives: 0)

        let environmentMessages = try decodeMessages(try await nextNotificationPayload(notificationCapture))
        let connectedMessages = try decodeMessages(try await nextNotificationPayload(notificationCapture))
        let environmentParams = try XCTUnwrap(environmentMessages[0]["params"] as? [String: Any])
        XCTAssertEqual(environmentParams["status"] as? String, "connecting")
        XCTAssertEqual(environmentParams["installationId"] as? String, "install-1")
        XCTAssertEqual(environmentParams["environmentId"] as? String, "env-1")
        let connectedParams = try XCTUnwrap(connectedMessages[0]["params"] as? [String: Any])
        XCTAssertEqual(connectedMessages[0]["method"] as? String, "remoteControl/status/changed")
        XCTAssertEqual(connectedParams["status"] as? String, "connected")
        XCTAssertEqual(connectedParams["installationId"] as? String, "install-1")
        XCTAssertEqual(connectedParams["environmentId"] as? String, "env-1")
    }

    func testRemoteControlAppServerExecutableRuntimeRetriesAccountIDWaitBeforeConnectingLikeRust() async throws {
        let temp = try TemporaryDirectory()
        let clientID = RemoteControlClientID("client-1")
        let streamID = RemoteControlStreamID("stream-1")
        let transport = RemoteControlAppServerRecordingWebSocketTransport(incoming: [
            .text(try remoteControlEnvelopeText(RemoteControlClientEnvelope(
                event: .ping,
                clientID: clientID,
                streamID: streamID,
                seqID: nil,
                cursor: nil
            ))),
        ])
        let probe = RemoteControlAppServerExecutableRetryProbe(transport: transport)
        var runtime = RemoteControlAppServerExecutableRuntime(
            runtime: try RemoteControlRuntimeCore(
                remoteControlURL: "https://chatgpt.com/backend-api",
                installationID: "install-1",
                requestedEnabled: true,
                stateDatabaseAvailable: true
            ),
            configuration: testConfiguration(codexHome: temp.url),
            connect: { target, appServerClientName in
                try await probe.connect(target: target, appServerClientName: appServerClientName)
            }
        )

        try await runtime.run(maxReceives: 1, sleep: { seconds in
            await probe.sleep(seconds)
        })

        let attempts = await probe.connections()
        XCTAssertEqual(attempts.count, 2)
        XCTAssertEqual(attempts.map(\.target), [
            RemoteControlTarget(
                websocketURL: "wss://chatgpt.com/backend-api/wham/remote/control/server",
                enrollURL: "https://chatgpt.com/backend-api/wham/remote/control/server/enroll"
            ),
            RemoteControlTarget(
                websocketURL: "wss://chatgpt.com/backend-api/wham/remote/control/server",
                enrollURL: "https://chatgpt.com/backend-api/wham/remote/control/server/enroll"
            ),
        ])
        let sleeps = await probe.sleeps()
        XCTAssertEqual(sleeps, [RemoteControlConnectLoopCore.accountIDRetryIntervalSeconds])
        let frames = await transport.sentFrames()
        XCTAssertEqual(frames.count, 1)
        XCTAssertEqual(
            try remoteControlServerEnvelope(from: try XCTUnwrap(frames.first)),
            RemoteControlServerEnvelope(
                event: .pong(status: .unknown),
                clientID: clientID,
                streamID: streamID,
                seqID: 1
            )
        )
    }

    func testRemoteControlAppServerBridgeDropsUnknownAndClosesConnectionLikeRust() async throws {
        let temp = try TemporaryDirectory()
        let clientID = RemoteControlClientID("client-1")
        let streamID = RemoteControlStreamID("stream-1")
        let connectionID = RemoteControlVirtualConnectionID(7)
        let threadStateManager = AppServerThreadStateManager()
        var bridge = RemoteControlAppServerBridge(
            configuration: testConfiguration(codexHome: temp.url),
            threadStateManager: threadStateManager
        )
        let initialize = ExecServerJSONRPCMessage.request(ExecServerJSONRPCRequest(
            id: .integer(1),
            method: "initialize",
            params: .object([
                "clientInfo": .object([
                    "name": .string("test"),
                    "version": .string("0")
                ])
            ])
        ))
        let startThread = ExecServerJSONRPCMessage.request(ExecServerJSONRPCRequest(
            id: .integer(2),
            method: "thread/start",
            params: .object(["modelProvider": .string("mock_provider")])
        ))

        let unknownStep = await bridge.handle(.incomingMessage(connectionID: connectionID, message: initialize))
        XCTAssertEqual(unknownStep.droppedUnknownConnectionIDs, [connectionID])

        _ = await bridge.handle(.connectionOpened(
            connectionID: connectionID,
            clientID: clientID,
            streamID: streamID
        ))
        _ = await bridge.handle(.incomingMessage(connectionID: connectionID, message: initialize))
        let startStep = await bridge.handle(.incomingMessage(connectionID: connectionID, message: startThread))
        let startResponse = try response(with: .integer(2), in: startStep.outgoingMessages)
        guard case let .object(startResult) = startResponse.result,
              case let .object(thread)? = startResult["thread"],
              case let .string(threadID)? = thread["id"]
        else {
            return XCTFail("thread/start response did not include a thread id")
        }
        let subscribedBeforeClose = await threadStateManager.subscribedConnectionIDs(forThreadID: threadID)
        XCTAssertEqual(subscribedBeforeClose, [7])

        _ = await bridge.handle(.connectionClosed(connectionID: connectionID))

        let subscribedAfterClose = await threadStateManager.subscribedConnectionIDs(forThreadID: threadID)
        let loadedThreadIDs = await threadStateManager.listLoadedThreadIDs()
        XCTAssertEqual(subscribedAfterClose, [])
        XCTAssertEqual(loadedThreadIDs, [threadID])
        let afterClose = await bridge.handle(.incomingMessage(connectionID: connectionID, message: startThread))
        XCTAssertEqual(afterClose.droppedUnknownConnectionIDs, [connectionID])
    }

    func testAppServerWebSocketTransportServesHealthAndRejectsOriginLikeRust() async throws {
        let temp = try TemporaryDirectory()
        let transport = AppServerWebSocketTransport(configuration: testConfiguration(codexHome: temp.url))
        let (stream, continuation) = AsyncStream.makeStream(of: String.self)
        let serverTask = Task.detached {
            try await transport.run(host: "127.0.0.1", port: 0) { url in
                continuation.yield(url.trimmingCharacters(in: .whitespacesAndNewlines))
            }
        }
        defer {
            serverTask.cancel()
        }

        var iterator = stream.makeAsyncIterator()
        let announcedURL = await iterator.next()
        let urlString = try XCTUnwrap(announcedURL)
        let httpBaseURL = try httpURL(fromWebSocketURL: urlString)

        let readyz = try await httpStatus(url: httpBaseURL.appendingPathComponent("readyz"))
        XCTAssertEqual(readyz, 200)

        let healthz = try await httpStatus(url: httpBaseURL.appendingPathComponent("healthz"))
        XCTAssertEqual(healthz, 200)

        var originRequest = URLRequest(url: httpBaseURL.appendingPathComponent("healthz"))
        originRequest.setValue("https://example.test", forHTTPHeaderField: "Origin")
        let originStatus = try await httpStatus(request: originRequest)
        XCTAssertEqual(originStatus, 403)

        let webSocket = URLSession.shared.webSocketTask(with: try XCTUnwrap(URL(string: urlString)))
        webSocket.resume()
        defer {
            webSocket.cancel(with: .goingAway, reason: nil)
        }
        try await webSocket.send(.string(#"{"id":1,"method":"initialize","params":{"clientInfo":{"name":"test","version":"0"}}}"#))
        let response = try decode(Data((try await receiveWebSocketText(webSocket)).utf8))
        XCTAssertEqual(response["id"] as? Int, 1)
    }

    func testAppServerWebSocketTransportEnforcesCapabilityTokenAuthLikeRust() async throws {
        let token = "super-secret-token"
        let digest = Array(SHA256.hash(data: Data(token.utf8)))
        let temp = try TemporaryDirectory()
        let transport = AppServerWebSocketTransport(
            configuration: testConfiguration(codexHome: temp.url),
            authPolicy: AppServerWebsocketAuthPolicy(mode: .capabilityToken(tokenSHA256: digest))
        )
        let (stream, continuation) = AsyncStream.makeStream(of: String.self)
        let serverTask = Task.detached {
            try await transport.run(host: "127.0.0.1", port: 0) { url in
                continuation.yield(url.trimmingCharacters(in: .whitespacesAndNewlines))
            }
        }
        defer {
            serverTask.cancel()
        }

        var iterator = stream.makeAsyncIterator()
        let announcedURL = await iterator.next()
        let urlString = try XCTUnwrap(announcedURL)
        let httpBaseURL = try httpURL(fromWebSocketURL: urlString)

        var missingAuthRequest = webSocketUpgradeRequest(url: httpBaseURL)
        let missingAuthStatus = try await httpStatus(request: missingAuthRequest)
        XCTAssertEqual(missingAuthStatus, 401)

        missingAuthRequest.setValue("Bearer wrong-token", forHTTPHeaderField: "Authorization")
        let wrongAuthStatus = try await httpStatus(request: missingAuthRequest)
        XCTAssertEqual(wrongAuthStatus, 401)

        var webSocketRequest = URLRequest(url: try XCTUnwrap(URL(string: urlString)))
        webSocketRequest.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        let webSocket = URLSession.shared.webSocketTask(with: webSocketRequest)
        webSocket.resume()
        defer {
            webSocket.cancel(with: .goingAway, reason: nil)
        }

        try await webSocket.send(.string(#"{"id":1,"method":"initialize","params":{"clientInfo":{"name":"test","version":"0"}}}"#))
        let response = try decode(Data((try await receiveWebSocketText(webSocket)).utf8))
        XCTAssertEqual(response["id"] as? Int, 1)
        XCTAssertNotNil(response["result"] as? [String: Any])
    }

    func testAppServerUnixSocketTransportUpgradesWebSocketAndCleansPrivateSocketLikeRust() async throws {
        let codexHome = URL(fileURLWithPath: "/tmp/csw-\(UUID().uuidString)", isDirectory: true)
        try FileManager.default.createDirectory(at: codexHome, withIntermediateDirectories: true)
        defer {
            try? FileManager.default.removeItem(at: codexHome)
        }
        let socketPath = codexHome
            .appendingPathComponent("app-server-control", isDirectory: true)
            .appendingPathComponent("app-server-control.sock", isDirectory: false)
            .path
        let transport = AppServerWebSocketTransport(configuration: testConfiguration(codexHome: codexHome))
        let (stream, continuation) = AsyncStream.makeStream(of: String.self)
        let serverTask = Task.detached {
            try await transport.run(socketPath: socketPath) { path in
                continuation.yield(path)
            }
        }
        defer {
            serverTask.cancel()
        }

        let announcedSocketPath = try await nextValueWithTimeout(from: stream)
        XCTAssertEqual(announcedSocketPath, socketPath)
        let socketFD = try connectUnixSocket(path: socketPath)
        var socketClosed = false
        defer {
            if !socketClosed {
                Darwin.shutdown(socketFD, SHUT_RDWR)
                Darwin.close(socketFD)
            }
        }

        #if os(macOS)
        let attributes = try FileManager.default.attributesOfItem(atPath: socketPath)
        XCTAssertEqual((attributes[.posixPermissions] as? NSNumber)?.intValue, 0o600)
        #endif

        let handshake = [
            "GET /rpc HTTP/1.1",
            "Host: localhost",
            "Origin: https://example.test",
            "Upgrade: websocket",
            "Connection: Upgrade",
            "Sec-WebSocket-Key: dGhlIHNhbXBsZSBub25jZQ==",
            "Sec-WebSocket-Version: 13",
            "",
            "",
        ].joined(separator: "\r\n")
        try writeAll(Array(handshake.utf8), to: socketFD)
        let handshakeResponse = String(decoding: try readUntilHTTPHeaderEnd(from: socketFD), as: UTF8.self)
        XCTAssertTrue(handshakeResponse.hasPrefix("HTTP/1.1 101 Switching Protocols"))

        try writeWebSocketText(
            #"{"id":1,"method":"initialize","params":{"clientInfo":{"name":"unix-test","version":"0"}}}"#,
            to: socketFD
        )
        let responseText = try readWebSocketText(from: socketFD)
        let response = try decode(Data(responseText.utf8))
        XCTAssertEqual(response["id"] as? Int, 1)
        XCTAssertNotNil(response["result"] as? [String: Any])

        Darwin.shutdown(socketFD, SHUT_RDWR)
        Darwin.close(socketFD)
        socketClosed = true
        serverTask.cancel()
        _ = await serverTask.result
        XCTAssertFalse(FileManager.default.fileExists(atPath: socketPath))
    }

