    func testThreadStartInitializesOptionalLiveMCPServersWithoutRequiringThemLikeRust() throws {
        let temp = try TemporaryDirectory()
        let workingServer = try writeMCPServerScript(
            directory: temp.url,
            name: "working-optional-mcp.sh",
            contents: """
            #!/bin/sh
            count=0
            while IFS= read -r _line; do
                count=$((count + 1))
                if [ "$count" -ge 2 ]; then
                    printf '%s\\n' '{"jsonrpc":"2.0","id":1,"result":{"tools":[{"name":"lookup","description":"Look up docs.","inputSchema":{"type":"object"}}]}}'
                    exit 0
                fi
            done
            exit 1
            """
        )
        let failingServer = try writeMCPServerScript(
            directory: temp.url,
            name: "failing-optional-mcp.sh",
            contents: """
            #!/bin/sh
            while IFS= read -r _line; do
                exit 1
            done
            exit 1
            """
        )
        try """
        [mcp_servers.optional_docs]
        command = \(tomlTestString(workingServer.path))
        startup_timeout_sec = 1

        [mcp_servers.optional_broken]
        command = \(tomlTestString(failingServer.path))
        startup_timeout_sec = 1
        """.write(to: temp.url.appendingPathComponent("config.toml"), atomically: true, encoding: .utf8)
        let processor = try initializedProcessor(configuration: testConfiguration(codexHome: temp.url))

        let messages = try decodeMessages(processor.processLine(Data(
            #"{"id":1,"method":"thread/start","params":{"modelProvider":"mock_provider"}}"#.utf8
        )))

        let result = try XCTUnwrap(messages[0]["result"] as? [String: Any])
        let thread = try XCTUnwrap(result["thread"] as? [String: Any])
        let threadID = try XCTUnwrap(thread["id"] as? String)
        XCTAssertNil(processor.liveMcpStartupFailureMessage(threadID: threadID))
        let toolsByServer = try XCTUnwrap(processor.liveMcpToolsByServer(threadID: threadID))
        XCTAssertEqual(Set(toolsByServer.keys), ["optional_docs"])
        let docsTools = try XCTUnwrap(toolsByServer["optional_docs"])
        let lookup = try XCTUnwrap(docsTools["lookup"] as? [String: Any])
        XCTAssertEqual(lookup["description"] as? String, "Look up docs.")
        let startupStatuses = messages.compactMap { message -> [String: Any]? in
            guard message["method"] as? String == "mcpServer/startupStatus/updated" else {
                return nil
            }
            return message["params"] as? [String: Any]
        }
        XCTAssertEqual(startupStatuses.count, 4)
        XCTAssertEqual(startupStatuses[0]["name"] as? String, "optional_broken")
        XCTAssertEqual(startupStatuses[0]["status"] as? String, "starting")
        XCTAssertTrue(startupStatuses[0]["error"] is NSNull)
        XCTAssertEqual(startupStatuses[1]["name"] as? String, "optional_broken")
        XCTAssertEqual(startupStatuses[1]["status"] as? String, "failed")
        XCTAssertTrue((startupStatuses[1]["error"] as? String)?.contains("optional_broken") == true)
        XCTAssertEqual(startupStatuses[2]["name"] as? String, "optional_docs")
        XCTAssertEqual(startupStatuses[2]["status"] as? String, "starting")
        XCTAssertTrue(startupStatuses[2]["error"] is NSNull)
        XCTAssertEqual(startupStatuses[3]["name"] as? String, "optional_docs")
        XCTAssertEqual(startupStatuses[3]["status"] as? String, "ready")
        XCTAssertTrue(startupStatuses[3]["error"] is NSNull)
    }

    func testMcpServerStatusListReusesLiveManagerInventoryForLoadedThread() throws {
        let temp = try TemporaryDirectory()
        let inventoryLog = temp.url.appendingPathComponent("mcp-inventory.log", isDirectory: false)
        let workingServer = try writeMCPServerScript(
            directory: temp.url,
            name: "working-status-reuse-mcp.sh",
            contents: """
            #!/bin/sh
            count=0
            while IFS= read -r _line; do
                printf 'request\\n' >> \(inventoryLog.path)
                count=$((count + 1))
                if [ "$count" -eq 1 ]; then
                    printf '%s\\n' '{"jsonrpc":"2.0","id":0,"result":{"protocolVersion":"2025-06-18","capabilities":{},"serverInfo":{"name":"docs","version":"1.0.0"}}}'
                elif [ "$count" -eq 2 ]; then
                    printf '%s\\n' '{"jsonrpc":"2.0","id":1,"result":{"tools":[{"name":"lookup","description":"Live cached docs.","inputSchema":{"type":"object"}}]}}'
                elif [ "$count" -eq 3 ]; then
                    printf '%s\\n' '{"jsonrpc":"2.0","id":2,"result":{"resources":[{"name":"manual","uri":"test://docs/manual","mimeType":"text/markdown"}]}}'
                elif [ "$count" -eq 4 ]; then
                    printf '%s\\n' '{"jsonrpc":"2.0","id":3,"result":{"resourceTemplates":[{"name":"memo","uriTemplate":"test://docs/{id}","mimeType":"text/plain"}]}}'
                    exit 0
                fi
            done
            exit 1
            """
        )
        try """
        [mcp_servers.docs]
        command = \(tomlTestString(workingServer.path))
        startup_timeout_sec = 1
        """.write(to: temp.url.appendingPathComponent("config.toml"), atomically: true, encoding: .utf8)
        let processor = try initializedProcessor(configuration: testConfiguration(codexHome: temp.url))

        _ = try decodeMessages(processor.processLine(Data(
            #"{"id":1,"method":"thread/start","params":{"modelProvider":"mock_provider"}}"#.utf8
        )))
        XCTAssertEqual(try String(contentsOf: inventoryLog, encoding: .utf8), "request\nrequest\n")

        let response = try decode(processor.processLine(Data(
            #"{"id":2,"method":"mcpServerStatus/list","params":{"detail":"toolsAndAuthOnly"}}"#.utf8
        )))

        let result = try XCTUnwrap(response["result"] as? [String: Any])
        let data = try XCTUnwrap(result["data"] as? [[String: Any]])
        let status = try XCTUnwrap(data.first)
        XCTAssertEqual(status["name"] as? String, "docs")
        let tools = try XCTUnwrap(status["tools"] as? [String: [String: Any]])
        XCTAssertEqual(tools["lookup"]?["description"] as? String, "Live cached docs.")
        XCTAssertEqual(try String(contentsOf: inventoryLog, encoding: .utf8), "request\nrequest\n")

        let fullResponse = try decode(processor.processLine(Data(
            #"{"id":3,"method":"mcpServerStatus/list","params":{"detail":"full"}}"#.utf8
        )))

        let fullResult = try XCTUnwrap(fullResponse["result"] as? [String: Any])
        let fullData = try XCTUnwrap(fullResult["data"] as? [[String: Any]])
        let fullStatus = try XCTUnwrap(fullData.first)
        XCTAssertEqual(fullStatus["name"] as? String, "docs")
        let fullTools = try XCTUnwrap(fullStatus["tools"] as? [String: [String: Any]])
        XCTAssertEqual(fullTools["lookup"]?["description"] as? String, "Live cached docs.")
        let resources = try XCTUnwrap(fullStatus["resources"] as? [[String: Any]])
        XCTAssertEqual(resources.map { $0["uri"] as? String }, ["test://docs/manual"])
        let resourceTemplates = try XCTUnwrap(fullStatus["resourceTemplates"] as? [[String: Any]])
        XCTAssertEqual(resourceTemplates.map { $0["uriTemplate"] as? String }, ["test://docs/{id}"])
        XCTAssertEqual(
            try String(contentsOf: inventoryLog, encoding: .utf8),
            "request\nrequest\nrequest\nrequest\nrequest\nrequest\n"
        )
    }

