    func testTurnStartRecordsUserInputAndEmitsStartedNotification() throws {
        let temp = try TemporaryDirectory()
        let processor = try initializedProcessor(configuration: testConfiguration(codexHome: temp.url))
        let startMessages = try decodeMessages(processor.processLine(Data(#"{"id":1,"method":"thread/start","params":{"modelProvider":"mock_provider"}}"#.utf8)))
        let startResult = try XCTUnwrap(startMessages[0]["result"] as? [String: Any])
        let thread = try XCTUnwrap(startResult["thread"] as? [String: Any])
        let threadID = try XCTUnwrap(thread["id"] as? String)

        let messages = try decodeMessages(processor.processLine(Data(#"{"id":2,"method":"turn/start","params":{"threadId":"\#(threadID)","input":[{"type":"text","text":"Hello"},{"type":"image","url":"https://example.test/one.png"},{"type":"localImage","path":"/tmp/local-one.png","detail":"original"}]}}"#.utf8)))

        XCTAssertEqual(messages.count, 3)
        let result = try XCTUnwrap(messages[0]["result"] as? [String: Any])
        let turn = try XCTUnwrap(result["turn"] as? [String: Any])
        XCTAssertNotNil(turn["id"] as? String)
        XCTAssertEqual((turn["items"] as? [Any])?.count, 0)
        XCTAssertEqual(turn["itemsView"] as? String, "notLoaded")
        XCTAssertEqual(turn["status"] as? String, "inProgress")
        XCTAssertEqual(turn["error"] as? NSNull, NSNull())
        XCTAssertEqual(turn["startedAt"] as? NSNull, NSNull())
        XCTAssertEqual(turn["completedAt"] as? NSNull, NSNull())
        XCTAssertEqual(turn["durationMs"] as? NSNull, NSNull())
        XCTAssertEqual(messages[1]["method"] as? String, "turn/started")
        let notificationParams = try XCTUnwrap(messages[1]["params"] as? [String: Any])
        XCTAssertEqual(notificationParams["threadId"] as? String, threadID)
        let notificationTurn = try XCTUnwrap(notificationParams["turn"] as? [String: Any])
        XCTAssertEqual(notificationTurn["id"] as? String, turn["id"] as? String)
        XCTAssertEqual(messages[2]["method"] as? String, "thread/status/changed")
        let statusParams = try XCTUnwrap(messages[2]["params"] as? [String: Any])
        XCTAssertEqual(statusParams["threadId"] as? String, threadID)
        let status = try XCTUnwrap(statusParams["status"] as? [String: Any])
        XCTAssertEqual(status["type"] as? String, "active")
        XCTAssertEqual(status["activeFlags"] as? [String], [])

        let resume = try decode(processor.processLine(Data(#"{"id":3,"method":"thread/resume","params":{"threadId":"\#(threadID)"}}"#.utf8)))
        let resumeResult = try XCTUnwrap(resume["result"] as? [String: Any])
        let resumedThread = try XCTUnwrap(resumeResult["thread"] as? [String: Any])
        let turns = try XCTUnwrap(resumedThread["turns"] as? [[String: Any]])
        XCTAssertEqual(turns.count, 1)
        let items = try XCTUnwrap(turns[0]["items"] as? [[String: Any]])
        let content = try XCTUnwrap(items[0]["content"] as? [[String: Any]])
        XCTAssertEqual(content[0]["text"] as? String, "Hello")
        XCTAssertEqual(content[1]["url"] as? String, "https://example.test/one.png")
        XCTAssertEqual(content[2]["type"] as? String, "localImage")
        XCTAssertEqual(content[2]["path"] as? String, "/tmp/local-one.png")
        XCTAssertEqual(content[2]["detail"] as? String, "original")
    }

    func testTurnStartRunsTrustedUserPromptSubmitHooksLikeRust() throws {
        let temp = try TemporaryDirectory()
        let managedDir = try TemporaryDirectory()
        let command = #"printf '%s' '{"hookSpecificOutput":{"hookEventName":"UserPromptSubmit","additionalContext":"runtime hook context"}}'"#
        let requirementsPath = temp.url.appendingPathComponent("requirements.toml", isDirectory: false)
        try """
        approval_policy = "never"

        [hooks]
        managed_dir = "\(managedDir.url.path)"

        [[hooks.UserPromptSubmit]]

        [[hooks.UserPromptSubmit.hooks]]
        type = "command"
        command = '''\(command)'''
        statusMessage = "checking prompt"
        """.write(to: requirementsPath, atomically: true, encoding: .utf8)

        let processor = try initializedProcessor(configuration: testConfiguration(
            codexHome: temp.url,
            configLayerOverrides: ConfigLayerLoaderOverrides(requirementsPath: requirementsPath)
        ))
        let startMessages = try decodeMessages(processor.processLine(Data(
            #"{"id":1,"method":"thread/start","params":{"modelProvider":"mock_provider","approvalPolicy":"never"}}"#.utf8
        )))
        let startResult = try XCTUnwrap(startMessages[0]["result"] as? [String: Any])
        let thread = try XCTUnwrap(startResult["thread"] as? [String: Any])
        let threadID = try XCTUnwrap(thread["id"] as? String)

        let messages = try decodeMessages(processor.processLine(Data(
            #"{"id":2,"method":"turn/start","params":{"threadId":"\#(threadID)","input":[{"type":"text","text":"Hello hook"}]}}"#.utf8
        )))

        XCTAssertEqual(messages.map { $0["method"] as? String }, [
            nil,
            "hook/started",
            "hook/completed",
            "turn/started",
            "thread/status/changed"
        ])
        let startedParams = try XCTUnwrap(messages[1]["params"] as? [String: Any])
        XCTAssertEqual(startedParams["threadId"] as? String, threadID)
        XCTAssertEqual((startedParams["run"] as? [String: Any])?["eventName"] as? String, "userPromptSubmit")
        XCTAssertEqual((startedParams["run"] as? [String: Any])?["status"] as? String, "running")
        let completedParams = try XCTUnwrap(messages[2]["params"] as? [String: Any])
        XCTAssertEqual((completedParams["run"] as? [String: Any])?["status"] as? String, "completed")
        let entries = try XCTUnwrap((completedParams["run"] as? [String: Any])?["entries"] as? [[String: Any]])
        XCTAssertEqual(entries.first?["kind"] as? String, "context")
        XCTAssertEqual(entries.first?["text"] as? String, "runtime hook context")

        let rolloutPath = try XCTUnwrap(RolloutListing.findConversationPathByIDString(
            codexHome: temp.url,
            idString: threadID
        ))
        guard case let .resumed(history) = try RolloutRecorder.getRolloutHistory(
            path: URL(fileURLWithPath: rolloutPath)
        ) else {
            return XCTFail("expected resumed rollout history")
        }
        let userIndex = try XCTUnwrap(history.history.firstIndex {
            $0 == .eventMsg(.userMessage(UserMessageEvent(message: "Hello hook")))
        })
        let contextIndex = try XCTUnwrap(history.history.firstIndex {
            guard case let .responseItem(.message(_, role, content, _)) = $0 else {
                return false
            }
            return role == "developer" && content == [.inputText(text: "runtime hook context")]
        })
        XCTAssertLessThan(userIndex, contextIndex)
    }

    func testTurnStartRunsPendingSessionStartHooksBeforePromptLikeRust() throws {
        let temp = try TemporaryDirectory()
        let managedDir = try TemporaryDirectory()
        let hookScript = temp.url.appendingPathComponent("session-start-hook.sh", isDirectory: false)
        let hookLog = temp.url.appendingPathComponent("session-start-hook-input.json", isDirectory: false)
        try """
        #!/bin/sh
        cat >> "$1"
        printf '%s' '{"hookSpecificOutput":{"hookEventName":"SessionStart","additionalContext":"session hook context"}}'
        """.write(to: hookScript, atomically: true, encoding: .utf8)
        try FileManager.default.setAttributes([.posixPermissions: 0o755], ofItemAtPath: hookScript.path)
        let requirementsPath = temp.url.appendingPathComponent("requirements.toml", isDirectory: false)
        try """
        [hooks]
        managed_dir = "\(managedDir.url.path)"

        [[hooks.SessionStart]]
        matcher = "clear"

        [[hooks.SessionStart.hooks]]
        type = "command"
        command = '''\(hookScript.path) \(hookLog.path)'''
        statusMessage = "starting session"
        """.write(to: requirementsPath, atomically: true, encoding: .utf8)

        let processor = try initializedProcessor(configuration: testConfiguration(
            codexHome: temp.url,
            configLayerOverrides: ConfigLayerLoaderOverrides(requirementsPath: requirementsPath)
        ))
        let startMessages = try decodeMessages(processor.processLine(Data(
            #"{"id":1,"method":"thread/start","params":{"model":"gpt-session","modelProvider":"mock_provider","approvalPolicy":"never","sessionStartSource":"clear"}}"#.utf8
        )))
        let startResult = try XCTUnwrap(startMessages[0]["result"] as? [String: Any])
        let thread = try XCTUnwrap(startResult["thread"] as? [String: Any])
        let threadID = try XCTUnwrap(thread["id"] as? String)

        let messages = try decodeMessages(processor.processLine(Data(
            #"{"id":2,"method":"turn/start","params":{"threadId":"\#(threadID)","input":[{"type":"text","text":"Hello after session"}]}}"#.utf8
        )))

        XCTAssertEqual(messages.map { $0["method"] as? String }, [
            nil,
            "hook/started",
            "hook/completed",
            "turn/started",
            "thread/status/changed"
        ])
        let startedParams = try XCTUnwrap(messages[1]["params"] as? [String: Any])
        XCTAssertEqual(startedParams["threadId"] as? String, threadID)
        XCTAssertNotNil(startedParams["turnId"] as? String)
        XCTAssertEqual((startedParams["run"] as? [String: Any])?["eventName"] as? String, "sessionStart")
        XCTAssertEqual((startedParams["run"] as? [String: Any])?["status"] as? String, "running")
        let completedParams = try XCTUnwrap(messages[2]["params"] as? [String: Any])
        XCTAssertEqual(completedParams["turnId"] as? String, startedParams["turnId"] as? String)
        XCTAssertEqual((completedParams["run"] as? [String: Any])?["status"] as? String, "completed")
        let entries = try XCTUnwrap((completedParams["run"] as? [String: Any])?["entries"] as? [[String: Any]])
        XCTAssertEqual(entries.first?["kind"] as? String, "context")
        XCTAssertEqual(entries.first?["text"] as? String, "session hook context")

        let hookInput = try XCTUnwrap(
            JSONSerialization.jsonObject(with: Data(try String(contentsOf: hookLog, encoding: .utf8).utf8)) as? [String: Any]
        )
        XCTAssertEqual(hookInput["hook_event_name"] as? String, "SessionStart")
        XCTAssertEqual(hookInput["session_id"] as? String, threadID)
        XCTAssertEqual(hookInput["source"] as? String, "clear")
        XCTAssertEqual(hookInput["model"] as? String, "gpt-session")
        XCTAssertEqual(hookInput["permission_mode"] as? String, "bypassPermissions")
        XCTAssertEqual(hookInput["transcript_path"] as? NSNull, NSNull())
        XCTAssertNil(hookInput["turn_id"])

        let rolloutPath = try XCTUnwrap(RolloutListing.findConversationPathByIDString(
            codexHome: temp.url,
            idString: threadID
        ))
        guard case let .resumed(history) = try RolloutRecorder.getRolloutHistory(
            path: URL(fileURLWithPath: rolloutPath)
        ) else {
            return XCTFail("expected resumed rollout history")
        }
        let contextIndex = try XCTUnwrap(history.history.firstIndex {
            guard case let .responseItem(.message(_, role, content, _)) = $0 else {
                return false
            }
            return role == "developer" && content == [.inputText(text: "session hook context")]
        })
        let userIndex = try XCTUnwrap(history.history.firstIndex {
            $0 == .eventMsg(.userMessage(UserMessageEvent(message: "Hello after session")))
        })
        XCTAssertLessThan(contextIndex, userIndex)
    }

