    func testLiveRuntimeDispatchesExtensionLifecycleCallbacksWithStableStoresLikeRust() async throws {
        let temp = try TemporaryDirectory()
        let coreCapture = AppServerCoreOpCapture()
        let recorder = AppServerExtensionRecorder()
        var builder = ExtensionRegistryBuilder()
        builder.threadLifecycleContributor(recorder)
        builder.turnLifecycleContributor(recorder)
        builder.tokenUsageContributor(recorder)
        builder.promptContributor(recorder)
        builder.toolContributor(recorder)
        builder.approvalReviewContributor(recorder)
        let liveRuntime = AppServerLiveRuntimeCapture { submission in
            guard submission.turnID == "turn-3" else {
                return []
            }
            return [
                EventMessage.tokenCount(TokenCountEvent(
                    info: TokenUsageInfo(
                        totalTokenUsage: TokenUsage(totalTokens: 23),
                        lastTokenUsage: TokenUsage(totalTokens: 5)
                    ),
                    rateLimits: nil
                )),
                EventMessage.taskComplete(TaskCompleteEvent(
                    turnID: submission.turnID,
                    lastAgentMessage: "done"
                ))
            ]
        }
        let processor = try initializedProcessor(
            configuration: testConfiguration(
                codexHome: temp.url,
                extensionRegistry: builder.build()
            ),
            coreOpSubmitter: coreCapture.submit,
            liveRuntimeSubmitter: liveRuntime.submit,
            experimentalAPIEnabled: true
        )

        let startMessages = try decodeMessages(processor.processLine(Data(
            #"{"id":1,"method":"thread/start","params":{"model":"gpt-extension","modelProvider":"mock_provider"}}"#.utf8
        )))
        let startResult = try XCTUnwrap(startMessages[0]["result"] as? [String: Any])
        let thread = try XCTUnwrap(startResult["thread"] as? [String: Any])
        let threadID = try XCTUnwrap(thread["id"] as? String)

        _ = try decodeMessages(processor.processLine(Data(
            #"{"id":2,"method":"thread/resume","params":{"threadId":"\#(threadID)"}}"#.utf8
        )))
        _ = try decodeMessages(processor.processLine(Data(
            #"{"id":3,"method":"turn/start","params":{"threadId":"\#(threadID)","input":[{"type":"text","text":"Run extension callbacks"}]}}"#.utf8
        )))
        _ = try decodeMessages(processor.processLine(Data(
            #"{"id":4,"method":"turn/start","params":{"threadId":"\#(threadID)","input":[{"type":"text","text":"Abort extension callbacks"}]}}"#.utf8
        )))
        await processor.handleRuntimeEvent(
            threadID: threadID,
            turnID: "turn-4",
            event: EventMessage.turnAborted(TurnAbortedEvent(turnID: "turn-4", reason: .interrupted))
        )

        await processor.handleRuntimeEvent(
            threadID: threadID,
            turnID: "turn-3",
            event: EventMessage.shutdownComplete
        )

        XCTAssertEqual(recorder.records, [
            "thread-start:\(threadID):nil",
            "thread-resume:\(threadID):thread-started",
            "turn-start:turn-3:thread-started",
            "tokens:turn-3:23:turn-started",
            "turn-stop:turn-3:turn-started",
            "turn-start:turn-4:thread-started",
            "turn-abort:turn-4:interrupted",
            "thread-stop:\(threadID):thread-started"
        ])
        let firstSubmission = try XCTUnwrap(liveRuntime.submissions.first)
        XCTAssertEqual(firstSubmission.extensionPromptFragments, [
            .developerPolicy("live-prompt:thread-started")
        ])
        let extensionTool = try XCTUnwrap(firstSubmission.extensionToolSpecs.first)
        XCTAssertTrue(extensionTool.supportsParallelToolCalls)
        guard case let .function(tool) = extensionTool.spec else {
            return XCTFail("expected extension function tool")
        }
        XCTAssertEqual(tool.name, "extension/live_tool")
        XCTAssertEqual(tool.description, "Live tool sees thread-started")
        let extensionExecutor = try XCTUnwrap(firstSubmission.extensionRegisteredToolExecutor)
        let maybeExecution = await extensionExecutor(.functionCall(
            name: "live_tool",
            namespace: "extension/",
            arguments: #"{"value":1}"#,
            callID: "call-live-extension"
        ))
        let execution = try XCTUnwrap(maybeExecution)
        XCTAssertEqual(
            execution.output,
            .functionCallOutput(
                callID: "call-live-extension",
                output: FunctionCallOutputPayload(content: #""ok""#, success: true)
            )
        )
        let approvalReviewer = try XCTUnwrap(firstSubmission.extensionApprovalReviewer)
        let unclaimedReview = await approvalReviewer("leave this to the host")
        XCTAssertNil(unclaimedReview)
        let claimedReview = await approvalReviewer("claim this prompt")
        XCTAssertEqual(claimedReview, .approvedForSession)
    }

    func testTurnStartLiveRuntimeSubmissionCarriesLoadedMcpToolsAndHandlerLikeRust() async throws {
        let temp = try TemporaryDirectory()
        try """
        [mcp_servers.docs]
        url = "https://mcp.example.test/mcp"
        startup_timeout_sec = 3
        """.write(to: temp.url.appendingPathComponent("config.toml"), atomically: true, encoding: .utf8)

        let capture = MCPHTTPTransportCapture()
        let coreCapture = AppServerCoreOpCapture()
        let liveRuntime = AppServerLiveRuntimeCapture { _ in [] }
        let processor = try initializedProcessor(
            configuration: testConfiguration(
                codexHome: temp.url,
                requiresOpenAIAuth: false,
                environment: [
                    CodexConfigLayerLoader.managedConfigEnvironmentVariable: temp.url
                        .appendingPathComponent("missing-managed-config.toml", isDirectory: false)
                        .path
                ],
                mcpHTTPTransport: { request in
                    capture.append(request)
                    let body = try XCTUnwrap(request.httpBody)
                    let object = try XCTUnwrap(JSONSerialization.jsonObject(with: body) as? [String: Any])
                    switch object["method"] as? String {
                    case "initialize":
                        return URLSessionTransportResponse(
                            statusCode: 200,
                            headers: ["mcp-session-id": "live-mcp-session"],
                            body: Data(#"{"jsonrpc":"2.0","id":0,"result":{"protocolVersion":"2025-06-18","capabilities":{"tools":{}},"serverInfo":{"name":"docs","version":"1.0.0"}}}"#.utf8)
                        )
                    case "tools/list":
                        return URLSessionTransportResponse(
                            statusCode: 200,
                            body: Data(#"{"jsonrpc":"2.0","id":1,"result":{"tools":[{"name":"lookup","description":"Lookup docs.","inputSchema":{"type":"object","properties":{"query":{"type":"string"}},"required":["query"],"additionalProperties":false}}]}}"#.utf8)
                        )
                    case "resources/list":
                        return URLSessionTransportResponse(
                            statusCode: 200,
                            body: Data(#"{"jsonrpc":"2.0","id":2,"result":{"resources":[]}}"#.utf8)
                        )
                    case "resources/templates/list":
                        return URLSessionTransportResponse(
                            statusCode: 200,
                            body: Data(#"{"jsonrpc":"2.0","id":3,"result":{"resourceTemplates":[]}}"#.utf8)
                        )
                    case "tools/call":
                        let params = try XCTUnwrap(object["params"] as? [String: Any])
                        XCTAssertEqual(params["name"] as? String, "lookup")
                        XCTAssertEqual((params["arguments"] as? [String: Any])?["query"] as? String, "swift")
                        XCTAssertNotNil((params["_meta"] as? [String: Any])?["threadId"] as? String)
                        return URLSessionTransportResponse(
                            statusCode: 200,
                            body: Data(#"{"jsonrpc":"2.0","id":1,"result":{"content":[{"type":"text","text":"lookup result"}],"structuredContent":{"answer":"lookup result"},"isError":false}}"#.utf8)
                        )
                    default:
                        return URLSessionTransportResponse(
                            statusCode: 500,
                            body: Data(#"{"jsonrpc":"2.0","id":99,"error":{"code":-32601,"message":"unexpected method"}}"#.utf8)
                        )
                    }
                }
            ),
            coreOpSubmitter: coreCapture.submit,
            liveRuntimeSubmitter: liveRuntime.submit,
            experimentalAPIEnabled: true
        )

        let startMessages = try decodeMessages(processor.processLine(Data(
            #"{"id":1,"method":"thread/start","params":{"model":"gpt-mcp","modelProvider":"mock_provider"}}"#.utf8
        )))
        let startResult = try XCTUnwrap(startMessages[0]["result"] as? [String: Any])
        let thread = try XCTUnwrap(startResult["thread"] as? [String: Any])
        let threadID = try XCTUnwrap(thread["id"] as? String)

        let turnMessages = try decodeMessages(processor.processLine(Data(
            #"{"id":2,"method":"turn/start","params":{"threadId":"\#(threadID)","input":[{"type":"text","text":"Lookup docs"}]}}"#.utf8
        )))
        XCTAssertNil(turnMessages.first?["error"])

        let submission = try XCTUnwrap(liveRuntime.submissions.first)
        let tool = try XCTUnwrap(submission.mcpTools["mcp__docs__lookup"])
        XCTAssertEqual(tool.description, "Lookup docs.")
        let handler = try XCTUnwrap(submission.mcpToolCallHandler)
        let handlerResult = await handler(NonInteractiveExec.McpToolCallRequest(
            callID: "call-live-mcp",
            turnID: submission.turnID,
            server: "docs",
            tool: "lookup",
            arguments: .object(["query": .string("swift")])
        ))
        guard case let .success(callResult)? = handlerResult else {
            return XCTFail("expected successful live MCP tool call")
        }
        XCTAssertEqual(callResult.structuredContent, .object(["answer": .string("lookup result")]))
        XCTAssertEqual(callResult.isError, false)
        XCTAssertEqual(
            try capture.requests.map { request -> String in
                let body = try XCTUnwrap(request.httpBody)
                let object = try XCTUnwrap(JSONSerialization.jsonObject(with: body) as? [String: Any])
                return try XCTUnwrap(object["method"] as? String)
            },
            ["initialize", "tools/list", "initialize", "tools/call"]
        )
    }

