            filenameTimestamp: "2025-01-05T13-00-00",
            timestamp: "2025-01-05T13:00:00Z",
            preview: "Saved user message",
            provider: "mock_provider",
            cwd: temp.url.path
        )
        let manager = AppServerLiveRuntimeManager(configuration: testConfiguration(
