    func testThreadReadOverlaysLoadedRuntimeStatusLikeRust() async throws {
        let temp = try TemporaryDirectory()
        let threadID = try writeRollout(
            codexHome: temp.url,
            filenameTimestamp: "2025-01-05T12-00-00",
