            modelProvider: "openai",
            cwd: temp.url.path,
            cliVersion: "0.0.0-test",
            title: "worker",
            sandboxPolicy: "danger-full-access",
            approvalMode: "never",
            tokensUsed: 0
        ))
        let capture = LiveMultiAgentToolCapture()
        let executor = AppServerLiveMultiAgentToolExecutor(
            currentThreadID: rootThreadID,
            currentSessionSource: .vscode,
            stateStore: stateStore,
            waitTimeouts: MultiAgentV2WaitTimeouts(config: MultiAgentV2Config()),
            isTurnRunning: { _ in false },
            agentStatus: { threadID in
                await capture.status(threadID: threadID)
            },
            agentLastTaskMessage: { threadID in
                await capture.lastTaskMessage(threadID: threadID)
            },
            hasPendingMailboxItems: { threadID in
                await capture.hasPendingMailbox(threadID: threadID)
            },
            waitForMailboxChange: { threadID, timeoutMS in
                await capture.waitForMailboxChange(threadID: threadID, timeoutMilliseconds: timeoutMS)
            },
            queueMailboxCommunications: { threadID, communications in
                await capture.queue(threadID: threadID, communications: communications)
            },
            recordAgentLastTaskMessage: { threadID, message in
                await capture.recordLastTaskMessage(threadID: threadID, message: message)
            },
            submitPendingWorkTurnIfIdle: { threadID in
                await capture.submitPendingWork(threadID: threadID)
                return true
            },
            closeAgentThreads: { threadIDs in
                await capture.close(threadIDs: threadIDs)
            }
        )

        let queueOnly = await executor.execute(.functionCall(
            name: "send_message",
            arguments: #"{"target":"worker","message":"queued hello"}"#,
            callID: "call-send"
        ))
        let queueOnlyPayload = try Self.functionOutputPayload(queueOnly, callID: "call-send")
        XCTAssertEqual(queueOnlyPayload.content, "")
        XCTAssertEqual(queueOnlyPayload.success, true)
        let queuedAfterSend = await capture.queuedCommunications(threadID: workerThreadID.description)
        XCTAssertEqual(
            queuedAfterSend,
            [InterAgentCommunication(
                author: .root,
                recipient: workerPath,
                content: "queued hello",
                triggerTurn: false
            )]
        )
        let pendingAfterSend = await capture.pendingWorkThreadIDs()
        XCTAssertEqual(pendingAfterSend, [])

        let followup = await executor.execute(.functionCall(
            name: "followup_task",
            arguments: #"{"target":"/root/worker","message":"wake up"}"#,
            callID: "call-followup"
        ))
        let followupPayload = try Self.functionOutputPayload(followup, callID: "call-followup")
        XCTAssertEqual(followupPayload.content, "")
        XCTAssertEqual(followupPayload.success, true)
        let queuedAfterFollowup = await capture.queuedCommunications(threadID: workerThreadID.description)
        XCTAssertEqual(
            queuedAfterFollowup.last,
            InterAgentCommunication(
                author: .root,
                recipient: workerPath,
                content: "wake up",
                triggerTurn: true
            )
        )
        let pendingAfterFollowup = await capture.pendingWorkThreadIDs()
        XCTAssertEqual(pendingAfterFollowup, [workerThreadID.description])
        let runtimeEvents = try XCTUnwrap(followup?.runtimeEvents)
        XCTAssertEqual(runtimeEvents.count, 2)
        guard case let .collabAgentInteractionBegin(begin) = runtimeEvents[0] else {
            return XCTFail("expected collab interaction begin event")
        }
        XCTAssertEqual(begin.senderThreadID, rootThreadID)
        XCTAssertEqual(begin.receiverThreadID, workerThreadID)
        XCTAssertEqual(begin.prompt, "wake up")
        guard case let .collabAgentInteractionEnd(end) = runtimeEvents[1] else {
            return XCTFail("expected collab interaction end event")
        }
        XCTAssertEqual(end.receiverAgentNickname, "Bernoulli")
        XCTAssertEqual(end.receiverAgentRole, "explorer")
        XCTAssertEqual(end.status, .completed(nil))
    }

    func testLiveSpawnAgentRoutesRustV2ArgumentsAndEvents() async throws {
        let rootThreadID = ThreadId()
        let workerThreadID = ThreadId()
        let workerPath = try AgentPath.root.join("worker")
        let capture = LiveMultiAgentToolCapture()
        let executor = AppServerLiveMultiAgentToolExecutor(
            currentThreadID: rootThreadID,
            currentSessionSource: .vscode,
            stateStore: nil,
            waitTimeouts: MultiAgentV2WaitTimeouts(config: MultiAgentV2Config()),
            hideSpawnAgentMetadata: false,
            spawnAgent: { request in
                await capture.recordSpawnRequest(request)
                return LiveSpawnAgentResult(
                    threadID: workerThreadID,
                    agentPath: workerPath,
                    nickname: "Bernoulli",
                    role: "explorer",
                    model: "gpt-5.4",
                    reasoningEffort: .high,
                    status: .running
                )
            },
            isTurnRunning: { _ in false },
            agentStatus: { threadID in
                await capture.status(threadID: threadID)
            },
            agentLastTaskMessage: { _ in nil },
            hasPendingMailboxItems: { _ in false },
            waitForMailboxChange: { _, _ in false },
            queueMailboxCommunications: { _, _ in },
            recordAgentLastTaskMessage: { _, _ in },
            submitPendingWorkTurnIfIdle: { _ in false },
            closeAgentThreads: { _ in }
        )

        let spawn = await executor.execute(.functionCall(
            name: "spawn_agent",
            arguments: #"{"message":"inspect this repo","task_name":"worker","agent_type":"explorer","model":"gpt-5.4","reasoning_effort":"high","service_tier":"flex","fork_turns":"none"}"#,
            callID: "call-spawn"
        ))
        let payload = try Self.functionOutputPayload(spawn, callID: "call-spawn")
        XCTAssertEqual(payload.success, true)
        let spawnResult = try JSONDecoder().decode(
            SpawnAgentToolResultFixture.self,
            from: Data(payload.content.utf8)
        )
        XCTAssertEqual(spawnResult, SpawnAgentToolResultFixture(
            taskName: workerPath.description,
            nickname: "Bernoulli"
        ))
        let requests = await capture.recordedSpawnRequests()
        XCTAssertEqual(requests, [
            LiveSpawnAgentRequest(
                callID: "call-spawn",
                message: "inspect this repo",
                taskName: "worker",
                agentType: "explorer",
                model: "gpt-5.4",
                reasoningEffort: .high,
                serviceTier: "flex",
                forkMode: .none,
                childAgentPath: workerPath
            )
        ])
        let runtimeEvents = try XCTUnwrap(spawn?.runtimeEvents)
        XCTAssertEqual(runtimeEvents.count, 2)
        guard case let .collabAgentSpawnBegin(begin) = runtimeEvents[0] else {
            return XCTFail("expected spawn begin event")
        }
        XCTAssertEqual(begin.senderThreadID, rootThreadID)
        XCTAssertEqual(begin.prompt, "inspect this repo")
        XCTAssertEqual(begin.model, "gpt-5.4")
        XCTAssertEqual(begin.reasoningEffort, .high)
        guard case let .collabAgentSpawnEnd(end) = runtimeEvents[1] else {
            return XCTFail("expected spawn end event")
        }
        XCTAssertEqual(end.senderThreadID, rootThreadID)
        XCTAssertEqual(end.newThreadID, workerThreadID)
        XCTAssertEqual(end.newAgentNickname, "Bernoulli")
        XCTAssertEqual(end.newAgentRole, "explorer")
        XCTAssertEqual(end.status, .running)

        let legacyForkContext = await executor.execute(.functionCall(
            name: "spawn_agent",
            arguments: #"{"message":"x","task_name":"worker","fork_context":true}"#,
            callID: "call-fork-context"
        ))
        let legacyPayload = try Self.functionOutputPayload(legacyForkContext, callID: "call-fork-context")
        XCTAssertEqual(
            legacyPayload.content,
            "fork_context is not supported in MultiAgentV2; use fork_turns instead"
        )
        XCTAssertEqual(legacyPayload.success, false)

        let invalidForkTurns = await executor.execute(.functionCall(
            name: "spawn_agent",
            arguments: #"{"message":"x","task_name":"worker","fork_turns":"0"}"#,
            callID: "call-fork-zero"
        ))
        let invalidPayload = try Self.functionOutputPayload(invalidForkTurns, callID: "call-fork-zero")
        XCTAssertEqual(
            invalidPayload.content,
            "fork_turns must be `none`, `all`, or a positive integer string"
        )
        XCTAssertEqual(invalidPayload.success, false)

        let fullForkOverride = await executor.execute(.functionCall(
            name: "spawn_agent",
            arguments: #"{"message":"x","task_name":"worker","fork_turns":"all","model":"gpt-5.4"}"#,
            callID: "call-full-fork-model"
        ))
        let fullForkPayload = try Self.functionOutputPayload(fullForkOverride, callID: "call-full-fork-model")
        XCTAssertEqual(
            fullForkPayload.content,
            "Full-history forked agents inherit the parent agent type, model, and reasoning effort; omit agent_type, model, and reasoning_effort, or spawn without a full-history fork."
        )
        XCTAssertEqual(fullForkPayload.success, false)
        let fullForkEvents = try XCTUnwrap(fullForkOverride?.runtimeEvents)
        XCTAssertEqual(fullForkEvents.count, 1)
        guard case let .collabAgentSpawnBegin(fullForkBegin) = fullForkEvents[0] else {
            return XCTFail("expected full-history override rejection to emit spawn begin only")
        }
        XCTAssertEqual(fullForkBegin.model, "gpt-5.4")

        let emptyAgentType = await executor.execute(.functionCall(
            name: "spawn_agent",
            arguments: #"{"message":"x","task_name":"worker","agent_type":"   ","fork_turns":"none"}"#,
            callID: "call-empty-agent-type"
        ))
        let emptyAgentPayload = try Self.functionOutputPayload(emptyAgentType, callID: "call-empty-agent-type")
        XCTAssertEqual(emptyAgentPayload.success, true)
        let updatedRequests = await capture.recordedSpawnRequests()
        XCTAssertEqual(updatedRequests.last?.agentType, nil)
    }

    func testLiveSpawnAgentValidatesRustRoleModelReasoningAndServiceTierOverrides() async throws {
        let priorityTier = ModelServiceTier(
            id: ServiceTier.fast.requestValue,
            name: "fast",
            description: "Fastest inference with increased plan usage"
        )
        let gpt54 = ModelPreset(
            id: "gpt-5.4",
            model: "gpt-5.4",
            displayName: "GPT 5.4",
            description: "Strong model",
            defaultReasoningEffort: .medium,
            supportedReasoningEfforts: [
                ReasoningEffortPreset(effort: .medium, description: "Medium"),
                ReasoningEffortPreset(effort: .high, description: "High")
            ],
            serviceTiers: [priorityTier],
            isDefault: true,
            showInPicker: true,
            supportedInAPI: true
        )
        let codex53 = ModelPreset(
            id: "gpt-5.3-codex",
            model: "gpt-5.3-codex",
            displayName: "GPT 5.3 Codex",
            description: "Coding model",
            defaultReasoningEffort: .low,
            supportedReasoningEfforts: [
                ReasoningEffortPreset(effort: .low, description: "Low"),
                ReasoningEffortPreset(effort: .medium, description: "Medium")
            ],
            isDefault: false,
            showInPicker: true,
            supportedInAPI: true
        )
        let resolver = LiveSpawnAgentOverrideResolver(
            availableModels: [gpt54, codex53],
            currentModel: "gpt-5.4",
            currentModelDefaultReasoningEffort: .medium,
            parentServiceTier: ServiceTier.fast.requestValue,
            configuredAgentRoles: ["custom-role"]
        )

        XCTAssertThrowsError(try resolver.resolve(LiveSpawnAgentOverrideRequest(
            agentType: "missing-role",
            model: nil,
            reasoningEffort: nil,
            serviceTier: nil,
            forkMode: .none
        ))) { error in
            XCTAssertEqual((error as? AppServerLiveMultiAgentToolError)?.message, "unknown agent_type 'missing-role'")
        }
        XCTAssertThrowsError(try resolver.resolve(LiveSpawnAgentOverrideRequest(
            agentType: nil,
            model: "unknown-model",
            reasoningEffort: nil,
            serviceTier: nil,
            forkMode: .none
        ))) { error in
            XCTAssertEqual(
                (error as? AppServerLiveMultiAgentToolError)?.message,
                "Unknown model `unknown-model` for spawn_agent. Available models: gpt-5.4, gpt-5.3-codex"
            )
        }
        XCTAssertThrowsError(try resolver.resolve(LiveSpawnAgentOverrideRequest(
            agentType: nil,
            model: "gpt-5.4",
            reasoningEffort: .xhigh,
            serviceTier: nil,
            forkMode: .none
        ))) { error in
            XCTAssertEqual(
                (error as? AppServerLiveMultiAgentToolError)?.message,
                "Reasoning effort `xhigh` is not supported for model `gpt-5.4`. Supported reasoning efforts: medium, high"
            )
        }
        XCTAssertThrowsError(try resolver.resolve(LiveSpawnAgentOverrideRequest(
            agentType: nil,
            model: "gpt-5.4",
            reasoningEffort: nil,
            serviceTier: "turbo",
            forkMode: .none
        ))) { error in
            XCTAssertEqual(
                (error as? AppServerLiveMultiAgentToolError)?.message,
                "Service tier `turbo` is not supported for model `gpt-5.4`. Supported service tiers: priority"
            )
        }

        let modelDefault = try resolver.resolve(LiveSpawnAgentOverrideRequest(
            agentType: "custom-role",
            model: "gpt-5.3-codex",
            reasoningEffort: nil,
            serviceTier: nil,
            forkMode: .none
        ))
        XCTAssertEqual(modelDefault, LiveSpawnAgentResolvedOverrides(
            agentType: "custom-role",
            model: "gpt-5.3-codex",
            reasoningEffort: .low,
            serviceTier: nil
        ))

        let temp = try TemporaryDirectory()
        let roleFile = temp.url.appendingPathComponent("reviewer.toml", isDirectory: false)
        try """
        name = "reviewer"
        description = "Review code"
        developer_instructions = "Review carefully"
        model = "gpt-5.4"
        model_reasoning_effort = "high"
        service_tier = "priority"
        """.write(to: roleFile, atomically: true, encoding: .utf8)
        let roleConfigOverrides = try LiveSpawnAgentOverrideResolver.roleConfigOverrides(
            configuredAgentRoles: [
                "reviewer": AgentRoleConfig(
                    description: "Review code",
                    configFile: roleFile.path
                )
            ]
        )
        let roleResolver = LiveSpawnAgentOverrideResolver(
            availableModels: [gpt54, codex53],
            currentModel: "gpt-5.3-codex",
            currentModelDefaultReasoningEffort: .low,
            parentServiceTier: nil,
            configuredAgentRoles: ["reviewer"],
            roleConfigOverrides: roleConfigOverrides
        )
        let roleResolved = try roleResolver.resolve(LiveSpawnAgentOverrideRequest(
            agentType: "reviewer",
            model: "gpt-5.3-codex",
            reasoningEffort: nil,
            serviceTier: nil,
            forkMode: .none
        ))
        XCTAssertEqual(roleResolved, LiveSpawnAgentResolvedOverrides(
            agentType: "reviewer",
            model: "gpt-5.4",
            reasoningEffort: .high,
            serviceTier: "priority"
        ))

        let badRoleFile = temp.url.appendingPathComponent("bad-reviewer.toml", isDirectory: false)
        try """
        name = "bad-reviewer"
        description = "Bad reviewer"
        developer_instructions = "Review carefully"
        model_reasoning_effort = "maximum"
        """.write(to: badRoleFile, atomically: true, encoding: .utf8)
        XCTAssertThrowsError(try LiveSpawnAgentOverrideResolver.roleConfigOverrides(
            configuredAgentRoles: [
                "bad-reviewer": AgentRoleConfig(
                    description: "Bad reviewer",
                    configFile: badRoleFile.path
                )
            ]
        )) { error in
            XCTAssertEqual(
                (error as? AppServerLiveMultiAgentToolError)?.message,
                "agent type is currently not available"
            )
        }
    }

    func testLiveSpawnAgentValidationFailureEmitsBeginWithoutSpawnEndLikeRust() async throws {
        let rootThreadID = ThreadId()
        let executor = AppServerLiveMultiAgentToolExecutor(
            currentThreadID: rootThreadID,
            currentSessionSource: .vscode,
            stateStore: nil,
            waitTimeouts: MultiAgentV2WaitTimeouts(config: MultiAgentV2Config()),
            resolveSpawnAgentOverrides: { _ in
                throw AppServerLiveMultiAgentToolError(
                    message: "Service tier `turbo` is not supported for model `gpt-5.4`. Supported service tiers: priority"
                )
            },
            spawnAgent: { _ in
                XCTFail("spawn_agent validation failure should not attempt a child spawn")
                throw AppServerLiveMultiAgentToolError(message: "unexpected spawn")
            },
            isTurnRunning: { _ in false },
            agentStatus: { _ in .completed(nil) },
            agentLastTaskMessage: { _ in nil },
            hasPendingMailboxItems: { _ in false },
            waitForMailboxChange: { _, _ in false },
            queueMailboxCommunications: { _, _ in },
            recordAgentLastTaskMessage: { _, _ in },
            submitPendingWorkTurnIfIdle: { _ in false },
            closeAgentThreads: { _ in }
        )
        let spawn = await executor.execute(.functionCall(
            name: "spawn_agent",
            arguments: #"{"message":"inspect this repo","task_name":"worker","service_tier":"turbo","fork_turns":"none"}"#,
            callID: "call-invalid-tier"
        ))
        let payload = try Self.functionOutputPayload(spawn, callID: "call-invalid-tier")
        XCTAssertEqual(
            payload.content,
            "Service tier `turbo` is not supported for model `gpt-5.4`. Supported service tiers: priority"
        )
        XCTAssertEqual(payload.success, false)
        let runtimeEvents = try XCTUnwrap(spawn?.runtimeEvents)
        XCTAssertEqual(runtimeEvents.count, 1)
        guard case let .collabAgentSpawnBegin(begin) = runtimeEvents[0] else {
            return XCTFail("expected validation failure to emit spawn begin only")
        }
        XCTAssertEqual(begin.senderThreadID, rootThreadID)
        XCTAssertEqual(begin.prompt, "inspect this repo")
    }

    func testLiveSpawnLastNTurnsSelectsRecentForkTurnsLikeRust() throws {
        let sourceID = try ConversationId(string: "77e55044-10b1-426f-9247-bb680e5fe0c8")
        let workerPath = try AgentPath.root.join("worker")
        let items: [RolloutRecordItem] = [
            .responseItem(.message(role: "user", content: [.outputText(text: "u1")])),
            .responseItem(.message(role: "assistant", content: [.outputText(text: "a1")], phase: .finalAnswer)),
            .responseItem(InterAgentCommunication(
                author: .root,
                recipient: workerPath,
                content: "queued message",
                triggerTurn: false
            ).toResponseInputItem().responseItem()),
            .responseItem(.message(role: "assistant", content: [.outputText(text: "a2")], phase: .finalAnswer)),
            .responseItem(InterAgentCommunication(
                author: .root,
                recipient: workerPath,
                content: "triggered task",
                triggerTurn: true
            ).toResponseInputItem().responseItem()),
            .responseItem(.message(role: "assistant", content: [.outputText(text: "a3")], phase: .finalAnswer)),
            .responseItem(.message(role: "user", content: [.outputText(text: "u2")])),
            .responseItem(.message(role: "assistant", content: [.outputText(text: "a4")], phase: .finalAnswer)),
        ]
        let parentHistory = InitialHistory.resumed(ResumedHistory(
            conversationID: sourceID,
            history: items,
            rolloutPath: "/source.jsonl"
        ))

        XCTAssertEqual(
            LiveSpawnAgentForkMode.lastNTurns(2).initialHistory(from: parentHistory).rolloutItems,
            Array(items[4...])
        )
    }

    func testLiveListAgentsUsesRustAgentPathsStatusAndLastTaskMessages() async throws {
        let temp = try TemporaryDirectory()
        let stateStore = try SQLiteAgentGraphStore(databaseURL: temp.url.appendingPathComponent("state.sqlite3"))
        let rootThreadID = ThreadId()
        let workerThreadID = ThreadId()
        let nestedThreadID = ThreadId()
        let siblingThreadID = ThreadId()
        let closedThreadID = ThreadId()
        let workerPath = try AgentPath.root.join("worker")
        let nestedPath = try workerPath.join("nested")
        let siblingPath = try AgentPath.root.join("sibling")
        let closedPath = try AgentPath.root.join("closed")
        for (threadID, path, nickname) in [
            (closedThreadID, closedPath, "Euler"),
            (workerThreadID, workerPath, "Bernoulli"),
            (nestedThreadID, nestedPath, "Curie"),
            (siblingThreadID, siblingPath, "Dirac"),
        ] {
            try await stateStore.upsertThread(ThreadMetadata(
                id: threadID,
                rolloutPath: temp.url.appendingPathComponent("\(path.name).jsonl").path,
                createdAt: Date(timeIntervalSince1970: 1_700_000_000),
                updatedAt: Date(timeIntervalSince1970: 1_700_000_001),
                source: "vscode",
                agentNickname: nickname,
                agentRole: "explorer",
                agentPath: path.description,
                modelProvider: "openai",
                cwd: temp.url.path,
                cliVersion: "0.0.0-test",
                title: path.name,
                sandboxPolicy: "danger-full-access",
                approvalMode: "never",
                tokensUsed: 0
            ))
        }
        try await stateStore.upsertThreadSpawnEdge(
            parentThreadID: rootThreadID,
            childThreadID: closedThreadID,
            status: .closed
        )
        let capture = LiveMultiAgentToolCapture(runningThreadIDs: [rootThreadID.description, nestedThreadID.description])
        await capture.setStatus(threadID: workerThreadID.description, status: .completed("done"))
        let executor = AppServerLiveMultiAgentToolExecutor(
            currentThreadID: rootThreadID,
            currentSessionSource: .vscode,
            stateStore: stateStore,
            waitTimeouts: MultiAgentV2WaitTimeouts(config: MultiAgentV2Config()),
            isTurnRunning: { threadID in
                await capture.isRunning(threadID: threadID)
            },
            agentStatus: { threadID in
                await capture.status(threadID: threadID)
            },
            agentLastTaskMessage: { threadID in
                await capture.lastTaskMessage(threadID: threadID)
            },
            hasPendingMailboxItems: { threadID in
                await capture.hasPendingMailbox(threadID: threadID)
            },
            waitForMailboxChange: { threadID, timeoutMS in
                await capture.waitForMailboxChange(threadID: threadID, timeoutMilliseconds: timeoutMS)
            },
            queueMailboxCommunications: { threadID, communications in
                await capture.queue(threadID: threadID, communications: communications)
            },
            recordAgentLastTaskMessage: { threadID, message in
                await capture.recordLastTaskMessage(threadID: threadID, message: message)
            },
            submitPendingWorkTurnIfIdle: { _ in true },
            closeAgentThreads: { threadIDs in
                await capture.close(threadIDs: threadIDs)
            }
        )

        _ = await executor.execute(.functionCall(
            name: "send_message",
            arguments: #"{"target":"worker","message":"inspect the logs"}"#,
            callID: "call-send"
        ))
        let listAll = await executor.execute(.functionCall(
            name: "list_agents",
            arguments: #"{}"#,
            callID: "call-list-all"
        ))
        let listAllPayload = try Self.functionOutputPayload(listAll, callID: "call-list-all")
        XCTAssertEqual(listAllPayload.success, true)
        let allResult = try JSONDecoder().decode(
            ListAgentsToolResultFixture.self,
            from: Data(listAllPayload.content.utf8)
        )
        XCTAssertEqual(allResult.agents.map(\.agentName), [
            "/root",
            "/root/sibling",
            "/root/worker",
            "/root/worker/nested",
        ])
        XCTAssertEqual(allResult.agents[0].agentStatus, .running)
        XCTAssertEqual(allResult.agents[0].lastTaskMessage, "Main thread")
        XCTAssertEqual(allResult.agents[2].agentStatus, .completed("done"))
        XCTAssertEqual(allResult.agents[2].lastTaskMessage, "inspect the logs")
        XCTAssertEqual(allResult.agents[3].agentStatus, .running)
        XCTAssertNil(allResult.agents[3].lastTaskMessage)

        let listWorkerSubtree = await executor.execute(.functionCall(
            name: "list_agents",
            arguments: #"{"path_prefix":"worker"}"#,
            callID: "call-list-worker"
        ))
        let workerPayload = try Self.functionOutputPayload(listWorkerSubtree, callID: "call-list-worker")
        let workerResult = try JSONDecoder().decode(
            ListAgentsToolResultFixture.self,
            from: Data(workerPayload.content.utf8)
        )
        XCTAssertEqual(workerResult.agents.map(\.agentName), [
            "/root/worker",
            "/root/worker/nested",
        ])
    }

