        try FileManager.default.createDirectory(at: configDirectory, withIntermediateDirectories: true)
        try """
        {
          "apps": {
            "radar": {
              "id": "connector_radar",
              "name": "Radar"
            }
          }
        }
        """.write(
            to: configDirectory.appendingPathComponent("apps.json", isDirectory: false),
            atomically: true,
            encoding: .utf8
        )
        try """
