    func testPluginReadValidatesSourceAndReportsRemoteDisabledWhenPluginsDisabled() throws {
        let temp = try TemporaryDirectory()
        let marketplace = temp.url.appendingPathComponent("marketplace.json").path

        let missingPluginName = try appServerResponse(
            #"{"id":0,"method":"plugin/read","params":{"remoteMarketplaceName":"openai-curated"}}"#,
            codexHome: temp.url
        )
        let missingPluginNameError = try XCTUnwrap(missingPluginName["error"] as? [String: Any])
        XCTAssertEqual(missingPluginNameError["code"] as? Int, -32600)
        XCTAssertEqual(missingPluginNameError["message"] as? String, "missing field `pluginName`")

        let invalidPluginName = try appServerResponse(
            #"{"id":0,"method":"plugin/read","params":{"remoteMarketplaceName":"openai-curated","pluginName":1}}"#,
            codexHome: temp.url
        )
        let invalidPluginNameError = try XCTUnwrap(invalidPluginName["error"] as? [String: Any])
        XCTAssertEqual(invalidPluginNameError["code"] as? Int, -32600)
        XCTAssertEqual(
            invalidPluginNameError["message"] as? String,
            "Invalid request: invalid type: integer `1`, expected a string"
        )

        let invalidMarketplacePath = try appServerResponse(
            #"{"id":0,"method":"plugin/read","params":{"marketplacePath":1,"pluginName":"gmail"}}"#,
            codexHome: temp.url
        )
        let invalidMarketplacePathError = try XCTUnwrap(invalidMarketplacePath["error"] as? [String: Any])
        XCTAssertEqual(invalidMarketplacePathError["code"] as? Int, -32600)
        XCTAssertEqual(
            invalidMarketplacePathError["message"] as? String,
            "Invalid request: invalid type: integer `1`, expected a string"
        )

        let missingSource = try appServerResponse(
            #"{"id":1,"method":"plugin/read","params":{"pluginName":"gmail"}}"#,
            codexHome: temp.url
        )
        let missingSourceError = try XCTUnwrap(missingSource["error"] as? [String: Any])
        XCTAssertEqual(missingSourceError["code"] as? Int, -32600)
        XCTAssertEqual(
            missingSourceError["message"] as? String,
            "plugin/read requires exactly one of marketplacePath or remoteMarketplaceName"
        )

        let duplicateSource = try appServerResponse(
            #"{"id":2,"method":"plugin/read","params":{"marketplacePath":"\#(marketplace)","remoteMarketplaceName":"openai-curated","pluginName":"gmail"}}"#,
            codexHome: temp.url
        )
        let duplicateSourceError = try XCTUnwrap(duplicateSource["error"] as? [String: Any])
        XCTAssertEqual(duplicateSourceError["code"] as? Int, -32600)
        XCTAssertEqual(
            duplicateSourceError["message"] as? String,
            "plugin/read requires exactly one of marketplacePath or remoteMarketplaceName"
        )

        try """
        [features]
        plugins = false
        """.write(to: temp.url.appendingPathComponent("config.toml"), atomically: true, encoding: .utf8)
        let remoteDisabled = try appServerResponse(
            #"{"id":3,"method":"plugin/read","params":{"remoteMarketplaceName":"openai-curated","pluginName":"plugins~Plugin_gmail"}}"#,
            codexHome: temp.url
        )
        let remoteDisabledError = try XCTUnwrap(remoteDisabled["error"] as? [String: Any])
        XCTAssertEqual(remoteDisabledError["code"] as? Int, -32600)
        XCTAssertEqual(
            remoteDisabledError["message"] as? String,
            "remote plugin read is not enabled for marketplace openai-curated"
        )
    }

