            "Bearer chatgpt-token",
            "Bearer chatgpt-token"
        ])
        XCTAssertEqual(capture.requests.map { $0.value(forHTTPHeaderField: "chatgpt-account-id") }, [
            "account-123",
            "account-123",
            "account-123"
        ])
    }

