        XCTAssertEqual(toolInvalidToolTypeError["code"] as? Int, -32600)
        XCTAssertEqual(
            toolInvalidToolTypeError["message"] as? String,
            "Invalid request: invalid type: map, expected a string"
        )

        let resourceInvalidThread = try appServerResponse(
            #"{"id":1,"method":"mcpServer/resource/read","params":{"threadId":"not-a-thread","server":"filesystem","uri":"file:///tmp/a"}}"#,
            codexHome: temp.url
        )
        let resourceInvalidThreadError = try XCTUnwrap(resourceInvalidThread["error"] as? [String: Any])
        XCTAssertEqual(resourceInvalidThreadError["code"] as? Int, -32600)
        XCTAssertTrue((resourceInvalidThreadError["message"] as? String)?.hasPrefix("invalid thread id: ") == true)

        let resourceMissingThread = try appServerResponse(
            #"{"id":2,"method":"mcpServer/resource/read","params":{"threadId":"\#(threadID)","server":"filesystem","uri":"file:///tmp/a"}}"#,
            codexHome: temp.url
        )
        let resourceMissingThreadError = try XCTUnwrap(resourceMissingThread["error"] as? [String: Any])
        XCTAssertEqual(resourceMissingThreadError["code"] as? Int, -32600)
        XCTAssertEqual(resourceMissingThreadError["message"] as? String, "thread not found: \(threadID)")

        let toolMissingThreadRecord = try appServerResponse(
            #"{"id":3,"method":"mcpServer/tool/call","params":{"threadId":"\#(threadID)","server":"filesystem","tool":"read_file","arguments":{}}}"#,
            codexHome: temp.url
        )
        let toolMissingThreadRecordError = try XCTUnwrap(toolMissingThreadRecord["error"] as? [String: Any])
        XCTAssertEqual(toolMissingThreadRecordError["code"] as? Int, -32600)
        XCTAssertEqual(toolMissingThreadRecordError["message"] as? String, "thread not found: \(threadID)")

        let toolMaterializedButUnloadedThread = try appServerResponse(
            #"{"id":12,"method":"mcpServer/tool/call","params":{"threadId":"\#(materializedThreadID)","server":"filesystem","tool":"read_file","arguments":{}}}"#,
            codexHome: temp.url
        )
        let toolMaterializedButUnloadedThreadError = try XCTUnwrap(
            toolMaterializedButUnloadedThread["error"] as? [String: Any]
        )
        XCTAssertEqual(toolMaterializedButUnloadedThreadError["code"] as? Int, -32600)
        XCTAssertEqual(
            toolMaterializedButUnloadedThreadError["message"] as? String,
            "thread not found: \(materializedThreadID)"
        )
    }

