    func testRealtimeConversationRoutesRejectMalformedStringsLikeRust() throws {
        let temp = try TemporaryDirectory()
        try """
        [features]
        realtime_conversation = true
        """.write(
            to: temp.url.appendingPathComponent("config.toml"),
            atomically: true,
            encoding: .utf8
        )

        let processor = try initializedProcessor(configuration: testConfiguration(codexHome: temp.url))
        let startMessages = try decodeMessages(processor.processLine(
            Data(#"{"id":1,"method":"thread/start","params":{"modelProvider":"mock_provider"}}"#.utf8)
        ))
        let startResult = try XCTUnwrap(startMessages[0]["result"] as? [String: Any])
        let thread = try XCTUnwrap(startResult["thread"] as? [String: Any])
        let threadID = try XCTUnwrap(thread["id"] as? String)
        let expectedStringTypeError = "Invalid request: invalid type: integer `1`, expected a string"

        let cases = [
            (
                #"{"method":"thread/realtime/start","params":{"threadId":1,"outputModality":"text"}}"#,
                expectedStringTypeError
            ),
            (
                #"{"method":"thread/realtime/start","params":{"threadId":"\#(threadID)","outputModality":1}}"#,
                expectedStringTypeError
            ),
            (
                #"{"method":"thread/realtime/start","params":{"threadId":"\#(threadID)","outputModality":"audio","prompt":1}}"#,
                expectedStringTypeError
            ),
            (
                #"{"method":"thread/realtime/start","params":{"threadId":"\#(threadID)","outputModality":"audio","realtimeSessionId":1}}"#,
                expectedStringTypeError
            ),
            (
                #"{"method":"thread/realtime/start","params":{"threadId":"\#(threadID)","outputModality":"audio","transport":{"type":"webrtc","sdp":1}}}"#,
                expectedStringTypeError
            ),
            (
                #"{"method":"thread/realtime/start","params":{"threadId":"\#(threadID)","outputModality":"audio","voice":1}}"#,
                "Invalid request: invalid type: integer `1`, expected string or map"
            ),
            (
                #"{"method":"thread/realtime/start","params":{"threadId":"\#(threadID)","outputModality":"audio","voice":"bogus"}}"#,
                "Invalid request: unknown variant `bogus`, expected one of `alloy`, `arbor`, `ash`, `ballad`, `breeze`, `cedar`, `coral`, `cove`, `echo`, `ember`, `juniper`, `maple`, `marin`, `sage`, `shimmer`, `sol`, `spruce`, `vale`, `verse`"
            ),
            (
                #"{"method":"thread/realtime/start","params":{"threadId":"\#(threadID)","outputModality":"audio","transport":"webrtc"}}"#,
                "Invalid request: invalid type: string \"webrtc\", expected internally tagged enum ThreadRealtimeStartTransport"
            ),
            (
                #"{"method":"thread/realtime/appendAudio","params":{"threadId":"\#(threadID)","audio":"AA=="}}"#,
                "Invalid request: invalid type: string \"AA==\", expected struct ThreadRealtimeAudioChunk"
            ),
            (
                #"{"method":"thread/realtime/appendAudio","params":{"threadId":"\#(threadID)","audio":null}}"#,
                "Invalid request: invalid type: null, expected struct ThreadRealtimeAudioChunk"
            ),
            (
                #"{"method":"thread/realtime/appendAudio","params":{"threadId":"\#(threadID)","audio":{"data":1,"sampleRate":24000,"numChannels":1}}}"#,
                expectedStringTypeError
            ),
            (
                #"{"method":"thread/realtime/appendAudio","params":{"threadId":"\#(threadID)","audio":{"data":"AA==","sampleRate":24000,"numChannels":1,"itemId":1}}}"#,
                expectedStringTypeError
            ),
            (
                #"{"method":"thread/realtime/appendText","params":{"threadId":"\#(threadID)","text":1}}"#,
                expectedStringTypeError
            )
        ]

        for (index, testCase) in cases.enumerated() {
            let response = try appServerResponse(
                #"{"id":\#(index + 2),\#(testCase.0.dropFirst())"#,
                codexHome: temp.url,
                experimentalAPIEnabled: true
            )
            let error = try XCTUnwrap(response["error"] as? [String: Any])
            XCTAssertEqual(error["code"] as? Int, -32600)
            XCTAssertEqual(error["message"] as? String, testCase.1)
        }
    }

    func testMcpServerStatusListReturnsConfiguredServersAndPaginates() throws {
        let temp = try TemporaryDirectory()
        try """
        [mcp_servers.docs]
        command = "docs-mcp"
        args = ["--stdio"]

        [mcp_servers.github]
        url = "https://mcp.github.test/mcp"
        bearer_token_env_var = "GITHUB_TOKEN"
        """.write(to: temp.url.appendingPathComponent("config.toml"), atomically: true, encoding: .utf8)

        let configuration = CodexAppServerConfiguration(
            codexHome: temp.url,
            requiresOpenAIAuth: false,
            environment: [
                CodexConfigLayerLoader.managedConfigEnvironmentVariable: temp.url
                    .appendingPathComponent("missing-managed-config.toml", isDirectory: false)
                    .path
            ],
            mcpHTTPTransport: { _ in
                URLSessionTransportResponse(
                    statusCode: 503,
                    body: Data(#"{"jsonrpc":"2.0","id":0,"error":{"code":-32000,"message":"offline"}}"#.utf8)
                )
            }
        )

        let first = try appServerResponse(
            #"{"id":1,"method":"mcpServerStatus/list","params":{"limit":1}}"#,
            configuration: configuration
        )
        let firstResult = try XCTUnwrap(first["result"] as? [String: Any])
        let firstData = try XCTUnwrap(firstResult["data"] as? [[String: Any]])
        XCTAssertEqual(firstData.count, 1)
        XCTAssertEqual(firstData[0]["name"] as? String, "docs")
        XCTAssertEqual(firstData[0]["authStatus"] as? String, "unsupported")
        XCTAssertEqual((firstData[0]["tools"] as? [String: Any])?.count, 0)
        XCTAssertEqual((firstData[0]["resources"] as? [Any])?.count, 0)
        XCTAssertEqual((firstData[0]["resourceTemplates"] as? [Any])?.count, 0)
        XCTAssertEqual(firstResult["nextCursor"] as? String, "1")

        let second = try appServerResponse(
            #"{"id":2,"method":"mcpServerStatus/list","params":{"cursor":"1"}}"#,
            configuration: configuration
        )
        let secondResult = try XCTUnwrap(second["result"] as? [String: Any])
        let secondData = try XCTUnwrap(secondResult["data"] as? [[String: Any]])
        XCTAssertEqual(secondData.map { $0["name"] as? String }, ["github"])
        XCTAssertEqual(secondData[0]["authStatus"] as? String, "bearerToken")
        XCTAssertNil(secondResult["nextCursor"])

        let nullDetail = try appServerResponse(
            #"{"id":4,"method":"mcpServerStatus/list","params":{"detail":null}}"#,
            configuration: configuration
        )
        let nullDetailResult = try XCTUnwrap(nullDetail["result"] as? [String: Any])
        let nullDetailData = try XCTUnwrap(nullDetailResult["data"] as? [[String: Any]])
        XCTAssertEqual(nullDetailData.map { $0["name"] as? String }, ["docs", "github"])

        let toolsOnly = try appServerResponse(
            #"{"id":3,"method":"mcpServerStatus/list","params":{"detail":"toolsAndAuthOnly"}}"#,
            configuration: configuration
        )
        let toolsOnlyResult = try XCTUnwrap(toolsOnly["result"] as? [String: Any])
        let toolsOnlyData = try XCTUnwrap(toolsOnlyResult["data"] as? [[String: Any]])
        XCTAssertEqual(toolsOnlyData.map { $0["name"] as? String }, ["docs", "github"])
    }

