    func testMcpServerReloadQueuesRefreshForLoadedThreads() throws {
        let temp = try TemporaryDirectory()
        let workspace = try TemporaryDirectory()
        try FileManager.default.createDirectory(
            at: workspace.url.appendingPathComponent(".git", isDirectory: true),
            withIntermediateDirectories: true
        )
        try FileManager.default.createDirectory(
            at: workspace.url.appendingPathComponent(".codex", isDirectory: true),
            withIntermediateDirectories: true
        )
        try """
        mcp_oauth_credentials_store = "file"

        [mcp_servers.docs]
        command = "docs-server"
        args = ["--stdio"]
        startup_timeout_sec = 12
        """.write(to: temp.url.appendingPathComponent("config.toml"), atomically: true, encoding: .utf8)
        try """
        [mcp_servers.docs]
        command = "project-docs-server"
        args = ["--project"]
        startup_timeout_sec = 5
        """.write(
            to: workspace.url.appendingPathComponent(".codex/config.toml", isDirectory: false),
            atomically: true,
            encoding: .utf8
        )
        let capture = AppServerCoreOpCapture()
        let processor = try initializedProcessor(
            configuration: testConfiguration(codexHome: temp.url),
            coreOpSubmitter: capture.submit
        )
        let startPayload = #"{"id":1,"method":"thread/start","params":{"modelProvider":"mock_provider","cwd":"\#(workspace.url.path)"}}"#
        let start = try decodeMessages(processor.processLine(
            Data(startPayload.utf8)
        ))
        let threadID = try XCTUnwrap(((start[0]["result"] as? [String: Any])?["thread"] as? [String: Any])?["id"] as? String)

        let response = try decode(processor.processLine(
            Data(#"{"id":2,"method":"config/mcpServer/reload","params":{}}"#.utf8)
        ))

        let result = try XCTUnwrap(response["result"] as? [String: Any])
        XCTAssertTrue(result.isEmpty)
        let refresh = try XCTUnwrap(processor.pendingMcpServerRefreshConfig(threadID: threadID))
        XCTAssertEqual(refresh.mcpOAuthCredentialsStoreMode, .string("file"))
        guard case let .object(servers) = refresh.mcpServers,
              case let .object(docs)? = servers["docs"]
        else {
            return XCTFail("expected docs MCP server refresh config")
        }
        XCTAssertEqual(docs["command"], .string("project-docs-server"))
        XCTAssertEqual(docs["args"], .array([.string("--project")]))
        XCTAssertEqual(docs["startup_timeout_sec"], .double(5))
        XCTAssertEqual(capture.submissions, [
            SubmittedCoreOp(requestID: .integer(2), threadID: threadID, op: .refreshMcpServers(config: refresh))
        ])
    }

    func testMcpServerReloadRefreshesLiveMCPManagerForLoadedThread() throws {
        let temp = try TemporaryDirectory()
        let workingServer = try writeMCPServerScript(
            directory: temp.url,
            name: "working-required-mcp.sh",
            contents: """
            #!/bin/sh
            count=0
            while IFS= read -r _line; do
                count=$((count + 1))
                if [ "$count" -ge 2 ]; then
                    printf '%s\\n' '{"jsonrpc":"2.0","id":1,"result":{"tools":[]}}'
                    exit 0
                fi
            done
            exit 1
            """
        )
        try writeRequiredLiveMCPConfig(
            codexHome: temp.url,
            command: workingServer.path,
            serverNames: ["docs"]
        )
        let capture = AppServerCoreOpCapture()
        let processor = try initializedProcessor(
            configuration: testConfiguration(codexHome: temp.url),
            coreOpSubmitter: capture.submit
        )
        let start = try decodeMessages(processor.processLine(
            Data(#"{"id":1,"method":"thread/start","params":{"modelProvider":"mock_provider"}}"#.utf8)
        ))
        let threadID = try XCTUnwrap(
            ((start[0]["result"] as? [String: Any])?["thread"] as? [String: Any])?["id"] as? String
        )
        XCTAssertNil(processor.liveMcpStartupFailureMessage(threadID: threadID))

        let failingServer = try writeMCPServerScript(
            directory: temp.url,
            name: "failing-required-mcp.sh",
            contents: """
            #!/bin/sh
            count=0
            while IFS= read -r _line; do
                count=$((count + 1))
                if [ "$count" -ge 2 ]; then
                    exit 1
                fi
            done
            exit 1
            """
        )
        try writeRequiredLiveMCPConfig(
            codexHome: temp.url,
            command: failingServer.path,
            serverNames: ["docs"]
        )

        let response = try decode(processor.processLine(
            Data(#"{"id":2,"method":"config/mcpServer/reload","params":{}}"#.utf8)
        ))

        let result = try XCTUnwrap(response["result"] as? [String: Any])
        XCTAssertTrue(result.isEmpty)
        XCTAssertEqual(
            processor.liveMcpStartupFailureMessage(threadID: threadID),
            "required MCP servers failed to initialize: docs: MCP server docs produced no response"
        )
        let refresh = try XCTUnwrap(processor.pendingMcpServerRefreshConfig(threadID: threadID))
        XCTAssertEqual(capture.submissions, [
            SubmittedCoreOp(requestID: .integer(2), threadID: threadID, op: .refreshMcpServers(config: refresh))
        ])
    }

