    func testHooksListReturnsUserCommandHooks() throws {
        let codexHome = try TemporaryDirectory()
        let cwd = try TemporaryDirectory()
        try """
        [hooks]

        [[hooks.PreToolUse]]
        matcher = "Bash"

        [[hooks.PreToolUse.hooks]]
