            "/tmp/disabled.sock": "none"
        ])
        XCTAssertEqual(network["allowUnixSockets"] as? [String], ["/tmp/codex.sock"])
        XCTAssertEqual(network["allowLocalBinding"] as? Bool, true)
    }

