        let negativeTimeout = try appServerResponse(
            #"{"id":6,"method":"command/exec","params":{"command":["/bin/echo","hi"],"cwd":"\#(cwd.url.path)","timeoutMs":-1}}"#,
            codexHome: codexHome.url
