    private func appServerResponse(
        _ line: String,
        configuration: CodexAppServerConfiguration,
        initializeFirst: Bool = true,
        experimentalAPIEnabled: Bool = false
    ) throws -> [String: Any] {
        let processor = CodexAppServerMessageProcessor(configuration: configuration)
        if initializeFirst {
            let capabilities = experimentalAPIEnabled ? #","capabilities":{"experimentalApi":true}"# : ""
            let initMessages = try decodeMessages(processor.processLine(Data(#"{"id":"init","method":"initialize","params":{"clientInfo":{"name":"test","version":"0"}\#(capabilities)}}"#.utf8)))
            XCTAssertEqual(initMessages.first?["id"] as? String, "init")
        }
        return try decode(processor.processLine(Data(line.utf8)))
    }

    private func initializedProcessor(
        configuration: CodexAppServerConfiguration,
        connectionID: AppServerConnectionID = 0,
        notificationSink: AppServerNotificationSink? = nil,
        coreOpSubmitter: AppServerCoreOpSubmitter? = nil,
        liveRuntimeSubmitter: AppServerLiveRuntimeSubmitter? = nil,
        threadStateManager: AppServerThreadStateManager = AppServerThreadStateManager(),
        experimentalAPIEnabled: Bool = false,
        optOutNotificationMethods: [String] = [],
        clientName: String = "test",
        clientVersion: String = "0"
    ) throws -> CodexAppServerMessageProcessor {
        let processor = CodexAppServerMessageProcessor(
            configuration: configuration,
            connectionID: connectionID,
            notificationSink: notificationSink,
            coreOpSubmitter: coreOpSubmitter,
            liveRuntimeSubmitter: liveRuntimeSubmitter,
            threadStateManager: threadStateManager
        )
        var capabilities: [String: Any] = [:]
        if experimentalAPIEnabled {
            capabilities["experimentalApi"] = true
        }
        if !optOutNotificationMethods.isEmpty {
            capabilities["optOutNotificationMethods"] = optOutNotificationMethods
        }
        var params: [String: Any] = [
            "clientInfo": [
                "name": clientName,
                "version": clientVersion
            ]
        ]
        if !capabilities.isEmpty {
            params["capabilities"] = capabilities
        }
        let request: [String: Any] = [
            "id": "init",
            "method": "initialize",
            "params": params
        ]
        let messages = try decodeMessages(processor.processLine(try JSONSerialization.data(withJSONObject: request)))
        XCTAssertEqual(messages.first?["id"] as? String, "init")
        return processor
    }

    private func startLoadedThread(
        processor: CodexAppServerMessageProcessor,
        cwd: String? = nil
    ) throws -> String {
        var params: [String: Any] = ["modelProvider": "mock_provider"]
        if let cwd {
            params["cwd"] = cwd
        }
        let request: [String: Any] = [
            "id": 99,
            "method": "thread/start",
            "params": params
        ]
        let messages = try decodeMessages(processor.processLine(try JSONSerialization.data(withJSONObject: request)))
        let result = try XCTUnwrap(messages.first?["result"] as? [String: Any])
        let thread = try XCTUnwrap(result["thread"] as? [String: Any])
        return try XCTUnwrap(thread["id"] as? String)
    }

