    private func nextNotificationPayload(
        _ capture: AppServerNotificationCapture,
        timeoutNanoseconds: UInt64 = 5_000_000_000
    ) async throws -> Data {
        let start = DispatchTime.now().uptimeNanoseconds
        while DispatchTime.now().uptimeNanoseconds - start < timeoutNanoseconds {
            if let payload = await capture.popPayload() {
                return payload
            }
            try await Task.sleep(nanoseconds: 10_000_000)
        }
        throw AppServerTestTimeout()
    }

    private func waitForTextFile(
        at url: URL,
        timeoutNanoseconds: UInt64 = 5_000_000_000
    ) async throws -> String {
        let start = DispatchTime.now().uptimeNanoseconds
        while DispatchTime.now().uptimeNanoseconds - start < timeoutNanoseconds {
            if let contents = try? String(contentsOf: url, encoding: .utf8), !contents.isEmpty {
                return contents
            }
            try await Task.sleep(nanoseconds: 10_000_000)
        }
        throw AppServerTestTimeout()
    }

    private func nextClientRequest(
        _ capture: AppServerNotificationCapture,
        method: String,
        timeoutNanoseconds: UInt64 = 5_000_000_000
    ) async throws -> [String: Any] {
        let start = DispatchTime.now().uptimeNanoseconds
        while DispatchTime.now().uptimeNanoseconds - start < timeoutNanoseconds {
            if let payload = await capture.popPayload(),
               let object = try JSONSerialization.jsonObject(with: payload) as? [String: Any],
               object["method"] as? String == method {
                return object
            }
            try await Task.sleep(nanoseconds: 10_000_000)
        }
        throw AppServerTestTimeout()
    }

    private func nextNotificationMessages(
        _ capture: AppServerNotificationCapture,
        method: String,
        timeoutNanoseconds: UInt64 = 5_000_000_000
    ) async throws -> [[String: Any]] {
        let start = DispatchTime.now().uptimeNanoseconds
        while DispatchTime.now().uptimeNanoseconds - start < timeoutNanoseconds {
            if let payload = await capture.popPayload() {
                let messages = try decodeMessages(payload)
                if messages.contains(where: { $0["method"] as? String == method }) {
                    return messages
                }
            }
            try await Task.sleep(nanoseconds: 10_000_000)
        }
        throw AppServerTestTimeout()
    }

    private func assertResolvedServerRequest(
        _ capture: AppServerNotificationCapture,
        threadID: String,
        requestID: Any,
        file: StaticString = #filePath,
        line: UInt = #line
    ) async throws {
        let messages = try await nextNotificationMessages(capture, method: "serverRequest/resolved")
        XCTAssertEqual(messages[0]["method"] as? String, "serverRequest/resolved", file: file, line: line)
        let params = try XCTUnwrap(messages[0]["params"] as? [String: Any], file: file, line: line)
        XCTAssertEqual(params["threadId"] as? String, threadID, file: file, line: line)
        XCTAssertEqual(
            (params["requestId"] as? NSNumber)?.int64Value,
            (requestID as? NSNumber)?.int64Value,
            file: file,
            line: line
        )
    }

    private func waitForSubmissions(
        _ capture: AppServerCoreOpCapture,
        count: Int,
        timeoutNanoseconds: UInt64 = 5_000_000_000
    ) async throws -> [SubmittedCoreOp] {
        let start = DispatchTime.now().uptimeNanoseconds
        while DispatchTime.now().uptimeNanoseconds - start < timeoutNanoseconds {
            let submissions = capture.submissions
            if submissions.count >= count {
                return submissions
            }
            try await Task.sleep(nanoseconds: 10_000_000)
        }
        throw AppServerTestTimeout()
    }

    private func startDynamicToolCall(
        processor: CodexAppServerMessageProcessor,
        notificationCapture: AppServerNotificationCapture,
        callID: String
    ) async throws -> Any {
        await processor.handleRuntimeEvent(
            threadID: "thread-1",
            turnID: "turn-fallback",
            event: .dynamicToolCallRequest(DynamicToolCallRequest(
                callID: callID,
                turnID: "turn-runtime",
                startedAtMilliseconds: 123,
                tool: "lookup",
                arguments: .object(["topic": .string("protocol")])
            ))
        )
        _ = try await nextNotificationPayload(notificationCapture)
        let requestData = try await nextNotificationPayload(notificationCapture)
        let request = try XCTUnwrap(JSONSerialization.jsonObject(with: requestData) as? [String: Any])
        XCTAssertEqual(request["method"] as? String, "item/tool/call")
        return try XCTUnwrap(request["id"])
    }

    private func dynamicToolResponseText(_ op: Op) -> String? {
        guard case let .dynamicToolResponse(_, response) = op,
              case let .text(text)? = response.contentItems.first
        else {
            return nil
        }
        return text
    }

    private func commandExecOutputDelta(
        _ message: [String: Any],
        processID: String
    ) throws -> (stream: String, text: String)? {
        guard message["method"] as? String == "command/exec/outputDelta",
              let params = message["params"] as? [String: Any],
              params["processId"] as? String == processID
        else {
            return nil
        }
        let stream = try XCTUnwrap(params["stream"] as? String)
        let deltaBase64 = try XCTUnwrap(params["deltaBase64"] as? String)
        let data = try XCTUnwrap(Data(base64Encoded: deltaBase64))
        return (stream, String(data: data, encoding: .utf8) ?? "")
    }

    private func waitForCommandLineMarker(
        _ marker: String,
        shouldExist: Bool,
        timeoutNanoseconds: UInt64 = 5_000_000_000
    ) async throws {
        let start = DispatchTime.now().uptimeNanoseconds
        while DispatchTime.now().uptimeNanoseconds - start < timeoutNanoseconds {
            if try commandLineMarkerExists(marker) == shouldExist {
                return
            }
            try await Task.sleep(nanoseconds: 50_000_000)
        }
        let expectation = shouldExist ? "appear" : "exit"
        XCTFail("process marker \(marker) did not \(expectation) before timeout")
        throw AppServerTestTimeout()
    }

    private func commandLineMarkerExists(_ marker: String) throws -> Bool {
        let process = Process()
        let output = Pipe()
        process.executableURL = URL(fileURLWithPath: "/bin/ps")
        process.arguments = ["-axo", "command"]
        process.standardOutput = output
        try process.run()
        let data = output.fileHandleForReading.readDataToEndOfFile()
        process.waitUntilExit()
        let commands = String(data: data, encoding: .utf8) ?? ""
        return commands.split(separator: "\n").contains { $0.contains(marker) }
    }

    private func archivedThreadIDs(from messages: [[String: Any]]) throws -> [String] {
        try messages.map { message in
            XCTAssertEqual(message["method"] as? String, "thread/archived")
