        codexHome: URL,
        command: String,
        serverNames: [String]
    ) throws {
        let config = serverNames.map { name in
            """
            [mcp_servers.\(name)]
            command = \(tomlTestString(command))
            required = true
            startup_timeout_sec = 1
            """
        }.joined(separator: "\n")
        try config.write(to: codexHome.appendingPathComponent("config.toml"), atomically: true, encoding: .utf8)
