            extensionRegistry: extensionRegistry,
            windowsSandboxSetupRunner: windowsSandboxSetupRunner
        )
    }

    private func skillContents(name: String, description: String, shortDescription: String? = nil) -> String {
        var lines = [
            "---",
            "name: \(name)",
            "description: \(description)"
        ]
        if let shortDescription {
            lines.append("metadata:")
            lines.append("  short-description: \(shortDescription)")
        }
        lines.append("---")
        lines.append("body")
        return lines.joined(separator: "\n") + "\n"
    }

    private func temporaryPrivateTmpDirectory() throws -> URL {
        let url = URL(fileURLWithPath: "/private/tmp/codex-swift-\(UUID().uuidString)", isDirectory: true)
        try FileManager.default.createDirectory(at: url, withIntermediateDirectories: true)
        return url
    }

    private func decode(_ data: Data?) throws -> [String: Any] {
        let data = try XCTUnwrap(data)
        return try XCTUnwrap(JSONSerialization.jsonObject(with: data) as? [String: Any])
    }

    private func decodeMessages(_ data: Data?) throws -> [[String: Any]] {
        let data = try XCTUnwrap(data)
        let payload = String(data: data, encoding: .utf8) ?? ""
        return try payload.split(separator: "\n", omittingEmptySubsequences: false).map { line in
            let lineData = Data(line.utf8)
            return try XCTUnwrap(JSONSerialization.jsonObject(with: lineData) as? [String: Any])
        }
    }

    private func response(
        with id: RequestID,
        in messages: [RemoteControlAppServerBridgeOutgoingMessage],
        file: StaticString = #filePath,
        line: UInt = #line
    ) throws -> ExecServerJSONRPCResponse {
        for outgoing in messages {
            if case let .response(response) = outgoing.message, response.id == id {
                return response
            }
        }
        XCTFail("missing response with id \(id)", file: file, line: line)
        throw AppServerTestTimeout()
    }

    private func response(
        with id: RequestID,
        in envelopes: [RemoteControlQueuedServerEnvelope],
        file: StaticString = #filePath,
        line: UInt = #line
    ) throws -> ExecServerJSONRPCResponse {
        for envelope in envelopes {
            if case let .serverMessage(.response(response)) = envelope.event, response.id == id {
                return response
            }
        }
        XCTFail("missing response with id \(id)", file: file, line: line)
        throw AppServerTestTimeout()
    }

    private func remoteControlEnvelopeText(_ envelope: RemoteControlClientEnvelope) throws -> String {
        String(decoding: try JSONEncoder().encode(envelope), as: UTF8.self)
    }

    private func remoteControlServerEnvelope(
        from frame: RemoteControlWebsocketWriterFrame
    ) throws -> RemoteControlServerEnvelope {
        guard case let .text(text) = frame else {
            throw AppServerTestFailure("expected websocket text frame")
        }
        return try JSONDecoder().decode(RemoteControlServerEnvelope.self, from: Data(text.utf8))
    }

    private func receiveWebSocketText(_ webSocket: URLSessionWebSocketTask) async throws -> String {
        switch try await webSocket.receive() {
        case let .string(text):
            return text
        case let .data(data):
            return String(decoding: data, as: UTF8.self)
        @unknown default:
            XCTFail("unexpected websocket message")
            return ""
        }
    }

    private func httpURL(fromWebSocketURL urlString: String) throws -> URL {
        var components = try XCTUnwrap(URLComponents(string: urlString))
        components.scheme = "http"
        return try XCTUnwrap(components.url)
    }

    private func webSocketUpgradeRequest(url: URL) -> URLRequest {
        var request = URLRequest(url: url)
        request.setValue("websocket", forHTTPHeaderField: "Upgrade")
        request.setValue("Upgrade", forHTTPHeaderField: "Connection")
        request.setValue("dGhlIHNhbXBsZSBub25jZQ==", forHTTPHeaderField: "Sec-WebSocket-Key")
        request.setValue("13", forHTTPHeaderField: "Sec-WebSocket-Version")
        return request
    }

    private func httpStatus(url: URL) async throws -> Int {
        try await httpStatus(request: URLRequest(url: url))
    }

    private func httpStatus(request: URLRequest) async throws -> Int {
        let (_, response) = try await URLSession.shared.data(for: request)
        let httpResponse = try XCTUnwrap(response as? HTTPURLResponse)
        return httpResponse.statusCode
    }

    private func nextValueWithTimeout(from stream: AsyncStream<String>, seconds: UInt64 = 5) async throws -> String? {
        try await withThrowingTaskGroup(of: String?.self) { group in
            group.addTask {
                var iterator = stream.makeAsyncIterator()
                return await iterator.next()
            }
            group.addTask {
                try await Task.sleep(nanoseconds: seconds * 1_000_000_000)
                return nil
            }
            let value = try await group.next()!
            group.cancelAll()
            return value
        }
    }

    private func connectUnixSocket(path: String) throws -> Int32 {
        let socketFD = Darwin.socket(AF_UNIX, SOCK_STREAM, 0)
        guard socketFD >= 0 else {
            throw NSError(domain: NSPOSIXErrorDomain, code: Int(errno))
        }

        do {
            var address = try unixSocketAddress(path: path)
            let result = withUnsafePointer(to: &address) { pointer in
                pointer.withMemoryRebound(to: sockaddr.self, capacity: 1) { sockaddrPointer in
                    Darwin.connect(socketFD, sockaddrPointer, socklen_t(MemoryLayout<sockaddr_un>.size))
                }
            }
            guard result == 0 else {
                throw NSError(domain: NSPOSIXErrorDomain, code: Int(errno))
            }
            return socketFD
        } catch {
            Darwin.close(socketFD)
            throw error
        }
    }

    private func unixSocketAddress(path: String) throws -> sockaddr_un {
        var address = sockaddr_un()
        #if os(macOS)
        address.sun_len = UInt8(MemoryLayout<sockaddr_un>.size)
        #endif
        address.sun_family = sa_family_t(AF_UNIX)

        let pathBytes = Array(path.utf8)
        let capacity = MemoryLayout.size(ofValue: address.sun_path)
        XCTAssertLessThan(pathBytes.count, capacity)

        withUnsafeMutablePointer(to: &address.sun_path) { pointer in
            pointer.withMemoryRebound(to: CChar.self, capacity: capacity) { buffer in
                for index in 0..<capacity {
                    buffer[index] = 0
                }
                for (index, byte) in pathBytes.enumerated() {
                    buffer[index] = CChar(bitPattern: byte)
                }
            }
        }

        return address
    }

    private func readUntilHTTPHeaderEnd(from fileDescriptor: Int32) throws -> [UInt8] {
        var bytes: [UInt8] = []
        while !bytes.suffix(4).elementsEqual([13, 10, 13, 10]) {
            bytes.append(contentsOf: try readExact(byteCount: 1, from: fileDescriptor))
        }
        return bytes
    }

    private func writeWebSocketText(_ text: String, to fileDescriptor: Int32) throws {
        try writeFrame(opcode: 0x1, payload: Array(text.utf8), masked: true, to: fileDescriptor)
    }

    private func readWebSocketText(from fileDescriptor: Int32) throws -> String {
        let header = try readExact(byteCount: 2, from: fileDescriptor)
        XCTAssertEqual(header[0] & 0x0F, 0x1)
        var payloadLength = Int(header[1] & 0x7F)
        if payloadLength == 126 {
            let bytes = try readExact(byteCount: 2, from: fileDescriptor)
            payloadLength = Int(bytes[0]) << 8 | Int(bytes[1])
        } else if payloadLength == 127 {
            let bytes = try readExact(byteCount: 8, from: fileDescriptor)
            payloadLength = bytes.reduce(Int(0)) { ($0 << 8) | Int($1) }
        }
        let payload = try readExact(byteCount: payloadLength, from: fileDescriptor)
        return String(decoding: payload, as: UTF8.self)
    }

    private func writeFrame(opcode: UInt8, payload: [UInt8], masked: Bool, to fileDescriptor: Int32) throws {
        var frame: [UInt8] = [0x80 | opcode]
        let maskBit: UInt8 = masked ? 0x80 : 0
        if payload.count < 126 {
            frame.append(maskBit | UInt8(payload.count))
        } else {
            frame.append(maskBit | 126)
            frame.append(UInt8((payload.count >> 8) & 0xFF))
            frame.append(UInt8(payload.count & 0xFF))
        }
        if masked {
            let mask: [UInt8] = [0x12, 0x34, 0x56, 0x78]
            frame += mask
            frame += payload.enumerated().map { index, byte in byte ^ mask[index % 4] }
        } else {
            frame += payload
        }
        try writeAll(frame, to: fileDescriptor)
    }

    private func readExact(byteCount: Int, from fileDescriptor: Int32) throws -> [UInt8] {
        var bytes = [UInt8](repeating: 0, count: byteCount)
        var offset = 0
        while offset < byteCount {
            try waitForSocket(fileDescriptor, events: Int16(POLLIN))
            let count = bytes.withUnsafeMutableBytes { buffer in
                Darwin.recv(fileDescriptor, buffer.baseAddress!.advanced(by: offset), byteCount - offset, 0)
            }
            if count == 0 {
                throw NSError(domain: NSPOSIXErrorDomain, code: Int(ECONNRESET))
            }
            guard count > 0 else {
                if errno == EINTR {
                    continue
                }
                throw NSError(domain: NSPOSIXErrorDomain, code: Int(errno))
            }
            offset += count
        }
        return bytes
    }

    private func writeAll(_ bytes: [UInt8], to fileDescriptor: Int32) throws {
        var offset = 0
        while offset < bytes.count {
            try waitForSocket(fileDescriptor, events: Int16(POLLOUT))
            let count = bytes.withUnsafeBytes { buffer in
                Darwin.send(fileDescriptor, buffer.baseAddress!.advanced(by: offset), bytes.count - offset, 0)
            }
            guard count >= 0 else {
                if errno == EINTR {
                    continue
                }
                throw NSError(domain: NSPOSIXErrorDomain, code: Int(errno))
            }
            offset += count
        }
    }

    private func waitForSocket(_ fileDescriptor: Int32, events: Int16) throws {
        var descriptor = pollfd(fd: fileDescriptor, events: events, revents: 0)
        let result = Darwin.poll(&descriptor, 1, 5_000)
        guard result > 0 else {
            if result == 0 {
                throw NSError(domain: NSPOSIXErrorDomain, code: Int(ETIMEDOUT))
            }
            throw NSError(domain: NSPOSIXErrorDomain, code: Int(errno))
        }
    }

    private func turnUserText(_ turn: [String: Any]) -> String {
        let items = turn["items"] as? [[String: Any]] ?? []
        guard let user = items.first(where: { $0["type"] as? String == "userMessage" }),
              let content = user["content"] as? [[String: Any]],
              let textItem = content.first(where: { $0["type"] as? String == "text" })
        else {
            return ""
        }
        return textItem["text"] as? String ?? ""
    }

    private func turnAgentTexts(_ turn: [String: Any]) -> [String] {
        let items = turn["items"] as? [[String: Any]] ?? []
        return items.compactMap { item in
            guard item["type"] as? String == "agentMessage" else {
                return nil
            }
            return item["text"] as? String
        }
    }

    private func assertNoCommandExecutionItems(
        _ turns: [[String: Any]],
        file: StaticString = #filePath,
        line: UInt = #line
    ) {
        for turn in turns {
            let items = turn["items"] as? [[String: Any]] ?? []
            XCTAssertFalse(
                items.contains { $0["type"] as? String == "commandExecution" },
                "persisted commandExecution items must stay out of reconstructed thread history",
                file: file,
                line: line
            )
        }
    }

    private func jsonString(_ value: String) -> String {
        let data = try! JSONEncoder().encode(value)
        return String(data: data, encoding: .utf8)!
    }

