    private func assertRestoredTokenUsageNotification(
        _ message: [String: Any],
        threadID: String,
        turnID: String,
        file: StaticString = #filePath,
        line: UInt = #line
    ) {
        XCTAssertEqual(message["method"] as? String, "thread/tokenUsage/updated", file: file, line: line)
        guard let params = message["params"] as? [String: Any],
              let tokenUsage = params["tokenUsage"] as? [String: Any],
              let total = tokenUsage["total"] as? [String: Any],
              let last = tokenUsage["last"] as? [String: Any]
        else {
            XCTFail("missing token usage notification payload", file: file, line: line)
            return
        }
        XCTAssertEqual(params["threadId"] as? String, threadID, file: file, line: line)
        XCTAssertEqual(params["turnId"] as? String, turnID, file: file, line: line)
        XCTAssertEqual(tokenUsage["modelContextWindow"] as? Int, 200_000, file: file, line: line)
        XCTAssertEqual(total["totalTokens"] as? Int, 150, file: file, line: line)
        XCTAssertEqual(total["inputTokens"] as? Int, 120, file: file, line: line)
        XCTAssertEqual(total["cachedInputTokens"] as? Int, 20, file: file, line: line)
        XCTAssertEqual(total["outputTokens"] as? Int, 30, file: file, line: line)
        XCTAssertEqual(total["reasoningOutputTokens"] as? Int, 10, file: file, line: line)
        XCTAssertEqual(last["totalTokens"] as? Int, 90, file: file, line: line)
    }

    @discardableResult
    private func writeRollout(
        codexHome: URL,
        filenameTimestamp: String,
        timestamp: String,
        preview: String,
        provider: String?,
        source: SessionSource = .cli,
        gitInfo: GitInfo? = nil,
        archived: Bool = false,
        cwd: String = "/",
        dynamicTools: [DynamicToolSpec]? = nil
    ) throws -> String {
        let id = UUID().uuidString.lowercased()
        let path = codexHome
            .appendingPathComponent(archived ? "archived_sessions" : "sessions/2025/01/02", isDirectory: true)
            .appendingPathComponent("rollout-\(filenameTimestamp)-\(id).jsonl", isDirectory: false)
        try FileManager.default.createDirectory(
            at: path.deletingLastPathComponent(),
            withIntermediateDirectories: true
        )
        let conversationID = try ConversationId(string: id)
        let meta = RolloutLine(
            timestamp: timestamp,
            item: .sessionMeta(SessionMetaLine(meta: SessionMeta(
                id: conversationID,
                timestamp: timestamp,
                cwd: cwd,
                originator: "codex_cli_rs",
                cliVersion: "0.0.0",
                source: source,
                modelProvider: provider,
                dynamicTools: dynamicTools
            ), git: gitInfo))
        )
        let user = RolloutLine(
            timestamp: timestamp,
            item: .eventMsg(.userMessage(UserMessageEvent(message: preview)))
        )
        let encoder = JSONEncoder()
        let lines = try [meta, user].map { line in
            String(data: try encoder.encode(line), encoding: .utf8)!
        }.joined(separator: "\n")
        try lines.write(to: path, atomically: true, encoding: .utf8)
        return id
    }

    private func firstSessionMetaPayload(at path: String) throws -> [String: Any] {
        let rollout = try String(contentsOfFile: path, encoding: .utf8)
        for rawLine in rollout.split(separator: "\n") {
            guard let object = try JSONSerialization.jsonObject(with: Data(rawLine.utf8)) as? [String: Any],
                  object["type"] as? String == "session_meta",
                  let payload = object["payload"] as? [String: Any]
            else {
                continue
            }
            return payload
        }
        return try XCTUnwrap(nil as [String: Any]?)
    }

    private func rolloutRecordTypes(at path: String) throws -> [String] {
        let rollout = try String(contentsOfFile: path, encoding: .utf8)
        return try rollout.split(separator: "\n").compactMap { rawLine in
            let object = try JSONSerialization.jsonObject(with: Data(rawLine.utf8)) as? [String: Any]
            return object?["type"] as? String
        }
    }

    private func appendRolloutEvents(to path: String, timestamp: String, events: [EventMessage]) throws {
        try appendRolloutItems(to: path, timestamp: timestamp, items: events.map(RolloutRecordItem.eventMsg))
    }

    private func appendRolloutItems(to path: String, timestamp: String, items: [RolloutRecordItem]) throws {
        let encoder = JSONEncoder()
        let lines = try items.map { item in
            let line = RolloutLine(timestamp: timestamp, item: item)
            return String(data: try encoder.encode(line), encoding: .utf8)!
        }.joined(separator: "\n")
        let url = URL(fileURLWithPath: path)
        let existing = try String(contentsOf: url, encoding: .utf8)
        try (existing + "\n" + lines).write(to: url, atomically: true, encoding: .utf8)
    }

    private func setModificationDate(_ timestamp: String, for threadID: String, codexHome: URL) throws {
        let formatter = ISO8601DateFormatter()
        formatter.formatOptions = [.withInternetDateTime]
        let date = try XCTUnwrap(formatter.date(from: timestamp))
        let path = try XCTUnwrap(RolloutListing.findConversationPathByIDString(
            codexHome: codexHome,
            idString: threadID
        ))
        try FileManager.default.setAttributes([.modificationDate: date], ofItemAtPath: path)
    }

    private func appServerDate(_ timestamp: String) throws -> Date {
        let formatter = ISO8601DateFormatter()
        formatter.formatOptions = timestamp.contains(".")
            ? [.withInternetDateTime, .withFractionalSeconds]
            : [.withInternetDateTime]
        return try XCTUnwrap(formatter.date(from: timestamp))
    }

