    private func sqliteCount(databaseURL: URL, query: String) throws -> Int {
        var database: OpaquePointer?
        XCTAssertEqual(sqlite3_open(databaseURL.path, &database), SQLITE_OK)
        let openedDatabase = try XCTUnwrap(database)
        defer {
            sqlite3_close(openedDatabase)
        }
        var statement: OpaquePointer?
        XCTAssertEqual(sqlite3_prepare_v2(openedDatabase, query, -1, &statement, nil), SQLITE_OK)
        let preparedStatement = try XCTUnwrap(statement)
        defer {
            sqlite3_finalize(preparedStatement)
        }
        XCTAssertEqual(sqlite3_step(preparedStatement), SQLITE_ROW)
        return Int(sqlite3_column_int64(preparedStatement, 0))
    }

    private func fakeJWT(email: String, plan: String, accountID: String = "acct-test") throws -> String {
        let header = ["alg": "none", "typ": "JWT"]
        let payload: [String: Any] = [
            "email": email,
            "https://api.openai.com/auth": [
                "chatgpt_plan_type": plan,
                "chatgpt_account_id": accountID
            ]
        ]
        return try [
            base64URL(header),
            base64URL(payload),
            "signature"
        ].joined(separator: ".")
    }

    private func createGitRepositoryWithRemote() throws -> (repo: URL, branch: String) {
        let temp = try TemporaryDirectory()
        retainedTemporaryDirectories.append(temp)
        let repo = temp.url.appendingPathComponent("repo", isDirectory: true)
        try FileManager.default.createDirectory(at: repo, withIntermediateDirectories: true)
        try runGit(["init"], cwd: repo)
        try runGit(["config", "user.name", "Test User"], cwd: repo)
        try runGit(["config", "user.email", "test@example.com"], cwd: repo)
        try "test content".write(to: repo.appendingPathComponent("test.txt"), atomically: true, encoding: .utf8)
        try runGit(["add", "test.txt"], cwd: repo)
        try runGit(["commit", "-m", "Initial commit"], cwd: repo)

        let remote = temp.url.appendingPathComponent("remote.git", isDirectory: true)
        try runGit(["init", "--bare", remote.path], cwd: temp.url)
        try runGit(["remote", "add", "origin", remote.path], cwd: repo)
        let branch = try runGit(["rev-parse", "--abbrev-ref", "HEAD"], cwd: repo)
            .stdout
            .trimmingCharacters(in: .whitespacesAndNewlines)
        try runGit(["push", "-u", "origin", branch], cwd: repo)
        return (repo, branch)
    }

    @discardableResult
    private func runGit(
        _ args: [String],
        cwd: URL
    ) throws -> (stdout: String, stderr: String) {
        let process = Process()
        process.executableURL = URL(fileURLWithPath: "/usr/bin/git")
        process.arguments = args
        process.currentDirectoryURL = cwd
        process.environment = [
            "GIT_CONFIG_GLOBAL": "/dev/null",
            "GIT_CONFIG_NOSYSTEM": "1"
        ]

        let stdoutPipe = Pipe()
        let stderrPipe = Pipe()
        process.standardOutput = stdoutPipe
        process.standardError = stderrPipe
        try process.run()
        process.waitUntilExit()

        let stdout = String(data: stdoutPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
        let stderr = String(data: stderrPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
        XCTAssertEqual(process.terminationStatus, 0, "git \(args.joined(separator: " ")) failed: \(stderr)")
        return (stdout, stderr)
    }

    private func createFIFO(at path: URL) throws {
        let mkfifo = "/usr/bin/mkfifo"
        guard FileManager.default.isExecutableFile(atPath: mkfifo) else {
            throw XCTSkip("mkfifo is unavailable on this platform")
        }

        let process = Process()
        process.executableURL = URL(fileURLWithPath: mkfifo)
        process.arguments = [path.path]
        let stdoutPipe = Pipe()
        let stderrPipe = Pipe()
        process.standardOutput = stdoutPipe
        process.standardError = stderrPipe
        try process.run()
        process.waitUntilExit()

        let stdout = String(data: stdoutPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
        let stderr = String(data: stderrPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
        XCTAssertEqual(process.terminationStatus, 0, "mkfifo failed: \(stderr)\(stdout)")
    }

    private func remotePluginBundleTarGzBytes(pluginRoot: URL, in tempRoot: URL) throws -> Data {
        let archive = tempRoot.appendingPathComponent("remote-plugin-bundle-\(UUID().uuidString).tar.gz", isDirectory: false)
        let process = Process()
        process.executableURL = URL(fileURLWithPath: "/usr/bin/tar")
        process.arguments = ["-czf", archive.path, "-C", pluginRoot.path, "."]
        let stdoutPipe = Pipe()
        let stderrPipe = Pipe()
        process.standardOutput = stdoutPipe
        process.standardError = stderrPipe
        try process.run()
        process.waitUntilExit()
        let stdout = String(data: stdoutPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
        let stderr = String(data: stderrPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
        XCTAssertEqual(process.terminationStatus, 0, "tar remote plugin bundle failed: \(stderr)\(stdout)")
        return try Data(contentsOf: archive)
    }

    private func curatedRepoZipballBytes(sha: String, in tempRoot: URL) throws -> Data {
        let sourceParent = tempRoot.appendingPathComponent("curated-zip-source-\(UUID().uuidString)", isDirectory: true)
        let sourceRoot = sourceParent.appendingPathComponent("openai-plugins-\(sha)", isDirectory: true)
        let manifestDirectory = sourceRoot.appendingPathComponent(".agents/plugins", isDirectory: true)
        let pluginManifestDirectory = sourceRoot
            .appendingPathComponent("plugins/gmail", isDirectory: true)
            .appendingPathComponent(".codex-plugin", isDirectory: true)
        try FileManager.default.createDirectory(at: manifestDirectory, withIntermediateDirectories: true)
        try FileManager.default.createDirectory(at: pluginManifestDirectory, withIntermediateDirectories: true)
        try """
        {
          "name": "openai-curated",
          "plugins": [
            {
              "name": "gmail",
              "source": "./plugins/gmail"
            }
          ]
        }
        """.write(
            to: manifestDirectory.appendingPathComponent("marketplace.json", isDirectory: false),
            atomically: true,
            encoding: .utf8
        )
        try """
        {
          "name": "gmail",
          "description": "Search mail"
        }
        """.write(
            to: pluginManifestDirectory.appendingPathComponent("plugin.json", isDirectory: false),
            atomically: true,
            encoding: .utf8
        )
        let archive = tempRoot.appendingPathComponent("curated-repo-\(UUID().uuidString).zip", isDirectory: false)
        let process = Process()
        process.executableURL = URL(fileURLWithPath: "/usr/bin/zip")
        process.arguments = ["-qry", archive.path, sourceRoot.lastPathComponent]
        process.currentDirectoryURL = sourceParent
        let stdoutPipe = Pipe()
        let stderrPipe = Pipe()
        process.standardOutput = stdoutPipe
        process.standardError = stderrPipe
        try process.run()
        process.waitUntilExit()
        let stdout = String(data: stdoutPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
        let stderr = String(data: stderrPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
        XCTAssertEqual(process.terminationStatus, 0, "zip curated repo failed: \(stderr)\(stdout)")
        return try Data(contentsOf: archive)
    }

    private func curatedRepoBackupArchiveZipBytes(sha: String, in tempRoot: URL) throws -> Data {
        let sourceParent = tempRoot.appendingPathComponent("curated-backup-source-\(UUID().uuidString)", isDirectory: true)
        let sourceRoot = sourceParent.appendingPathComponent("plugins", isDirectory: true)
        try FileManager.default.createDirectory(
            at: sourceRoot.appendingPathComponent(".git/refs/heads", isDirectory: true),
            withIntermediateDirectories: true
        )
        try FileManager.default.createDirectory(
            at: sourceRoot.appendingPathComponent(".agents/plugins", isDirectory: true),
            withIntermediateDirectories: true
        )
        try FileManager.default.createDirectory(
            at: sourceRoot.appendingPathComponent("plugins/gmail/.codex-plugin", isDirectory: true),
            withIntermediateDirectories: true
        )
        try "ref: refs/heads/main\n".write(
            to: sourceRoot.appendingPathComponent(".git/HEAD", isDirectory: false),
            atomically: true,
            encoding: .utf8
        )
        try "\(sha)\n".write(
            to: sourceRoot.appendingPathComponent(".git/refs/heads/main", isDirectory: false),
            atomically: true,
            encoding: .utf8
        )
        try """
        {
          "name": "openai-curated",
          "plugins": [
            {
              "name": "gmail",
              "source": "./plugins/gmail"
            }
          ]
        }
        """.write(
            to: sourceRoot.appendingPathComponent(".agents/plugins/marketplace.json", isDirectory: false),
            atomically: true,
            encoding: .utf8
        )
        try #"{"name":"gmail","description":"Search mail"}"#.write(
            to: sourceRoot.appendingPathComponent("plugins/gmail/.codex-plugin/plugin.json", isDirectory: false),
            atomically: true,
            encoding: .utf8
        )
        let archive = tempRoot.appendingPathComponent("curated-backup-\(UUID().uuidString).zip", isDirectory: false)
        let process = Process()
        process.executableURL = URL(fileURLWithPath: "/usr/bin/zip")
        process.arguments = ["-qry", archive.path, sourceRoot.lastPathComponent]
        process.currentDirectoryURL = sourceParent
        let stdoutPipe = Pipe()
        let stderrPipe = Pipe()
        process.standardOutput = stdoutPipe
        process.standardError = stderrPipe
        try process.run()
        process.waitUntilExit()
        let stdout = String(data: stdoutPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
        let stderr = String(data: stderrPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
        XCTAssertEqual(process.terminationStatus, 0, "zip curated backup failed: \(stderr)\(stdout)")
        return try Data(contentsOf: archive)
    }

    private func archiveContains(_ archiveBytes: Data, _ expectedPath: String, in tempRoot: URL) throws -> Bool {
        let archive = tempRoot.appendingPathComponent("share-upload-\(UUID().uuidString).tar.gz", isDirectory: false)
        try archiveBytes.write(to: archive)
        let process = Process()
        process.executableURL = URL(fileURLWithPath: "/usr/bin/tar")
        process.arguments = ["-tzf", archive.path]
        let stdoutPipe = Pipe()
        let stderrPipe = Pipe()
        process.standardOutput = stdoutPipe
        process.standardError = stderrPipe
        try process.run()
        process.waitUntilExit()
        let stdout = String(data: stdoutPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
        let stderr = String(data: stderrPipe.fileHandleForReading.readDataToEndOfFile(), encoding: .utf8) ?? ""
        XCTAssertEqual(process.terminationStatus, 0, "tar share upload listing failed: \(stderr)\(stdout)")
        try? FileManager.default.removeItem(at: archive)
        return stdout
            .split(separator: "\n")
            .map(String.init)
            .contains { $0 == expectedPath || $0 == "./\(expectedPath)" }
    }

    private func base64URL(_ object: Any) throws -> String {
        let data = try JSONSerialization.data(withJSONObject: object, options: [.sortedKeys])
        return data.base64EncodedString()
            .replacingOccurrences(of: "+", with: "-")
            .replacingOccurrences(of: "/", with: "_")
            .replacingOccurrences(of: "=", with: "")
    }

