    func record(target: RemoteControlTarget, appServerClientName: String?) {
        recordedConnections.append(Connection(target: target, appServerClientName: appServerClientName))
    }

    func connections() -> [Connection] {
        recordedConnections
    }
}

private actor RemoteControlAppServerExecutableRetryProbe {
    typealias Connection = RemoteControlAppServerExecutableConnectionProbe.Connection

    private let transport: RemoteControlAppServerRecordingWebSocketTransport
    private var recordedConnections: [Connection] = []
    private var recordedSleeps: [TimeInterval] = []

    init(transport: RemoteControlAppServerRecordingWebSocketTransport) {
        self.transport = transport
    }

    func connect(
        target: RemoteControlTarget,
        appServerClientName: String?
    ) throws -> RemoteControlAppServerExecutableConnection<RemoteControlAppServerRecordingWebSocketTransport> {
        recordedConnections.append(Connection(target: target, appServerClientName: appServerClientName))
        if recordedConnections.count == 1 {
            throw RemoteControlAuthLoadError.waitingForChatGPTAccountID
        }
        return RemoteControlAppServerExecutableConnection(
            transport: transport,
            environmentID: "env-1"
        )
    }

    func sleep(_ seconds: TimeInterval) {
        recordedSleeps.append(seconds)
    }

    func connections() -> [Connection] {
        recordedConnections
    }

    func sleeps() -> [TimeInterval] {
        recordedSleeps
    }
}

private actor AppServerDeviceCodeProbe {
    enum Scenario {
        case success(idToken: String)
        case userCodeFailure(statusCode: Int)
        case pending
    }

    private let scenario: Scenario

    init(scenario: Scenario) {
        self.scenario = scenario
    }

    func handle(_ request: URLRequest) throws -> AuthRefreshHTTPResponse {
        let url = request.url?.absoluteString ?? ""
        switch url {
        case "https://issuer.example/api/accounts/deviceauth/usercode":
            if case let .userCodeFailure(statusCode) = scenario {
                return AuthRefreshHTTPResponse(statusCode: statusCode, body: Data())
            }
            return AuthRefreshHTTPResponse(
                statusCode: 200,
                body: Data(#"{"device_auth_id":"device-auth-123","user_code":"CODE-12345","interval":"60"}"#.utf8)
            )

        case "https://issuer.example/api/accounts/deviceauth/token":
            if case .pending = scenario {
                return AuthRefreshHTTPResponse(statusCode: 404, body: Data())
            }
            return AuthRefreshHTTPResponse(
                statusCode: 200,
                body: Data(#"{"authorization_code":"poll-code-321","code_challenge":"code-challenge-321","code_verifier":"code-verifier-321"}"#.utf8)
            )

        case "https://issuer.example/oauth/token":
            guard case let .success(idToken) = scenario else {
                return AuthRefreshHTTPResponse(statusCode: 500, body: Data())
            }
            return AuthRefreshHTTPResponse(
                statusCode: 200,
                body: Data("""
                {
                  "id_token": "\(idToken)",
                  "access_token": "access-token-123",
                  "refresh_token": "refresh-token-123"
                }
                """.utf8)
            )

        default:
            return AuthRefreshHTTPResponse(statusCode: 404, body: Data())
        }
    }
}

private actor AppServerBrowserLoginProbe {
    private let idToken: String
    private let accessToken: String
    private var recordedRequests: [RecordedAppServerLoginRequest] = []

    init(idToken: String, accessToken: String) {
        self.idToken = idToken
        self.accessToken = accessToken
    }

    func handle(_ request: URLRequest) throws -> AuthRefreshHTTPResponse {
        let recorded = RecordedAppServerLoginRequest(request: request)
        recordedRequests.append(recorded)
        guard recorded.url == "https://auth.openai.com/oauth/token",
              let body = recorded.body
        else {
            return AuthRefreshHTTPResponse(statusCode: 404, body: Data())
        }

        if body.contains("grant_type=authorization_code") {
            return AuthRefreshHTTPResponse(
                statusCode: 200,
                body: Data("""
                {
                  "id_token": "\(idToken)",
                  "access_token": "\(accessToken)",
                  "refresh_token": "refresh-token"
                }
                """.utf8)
            )
        }

        if body.contains("requested_token=openai-api-key") {
            return AuthRefreshHTTPResponse(
                statusCode: 200,
                body: Data(#"{"access_token":"sk-exchanged"}"#.utf8)
            )
        }

        return AuthRefreshHTTPResponse(statusCode: 400, body: Data())
    }

    func requests() -> [RecordedAppServerLoginRequest] {
        recordedRequests
    }
}

private struct RecordedAppServerLoginRequest: Equatable, Sendable {
    let method: String
    let url: String
    let body: String?

    init(request: URLRequest) {
        method = request.httpMethod ?? "GET"
        url = request.url?.absoluteString ?? ""
        body = request.httpBody.flatMap { String(data: $0, encoding: .utf8) }
    }
}

private actor AppServerNotificationCapture {
    private var payloads: [Data] = []
    private var waiters: [CheckedContinuation<Data, Never>] = []

    func append(_ data: Data) {
        if !waiters.isEmpty {
            let waiter = waiters.removeFirst()
            waiter.resume(returning: data)
            return
        }
        payloads.append(data)
    }

    func payloadsData() -> [Data] {
        payloads
    }

    func popPayload() -> Data? {
        if !payloads.isEmpty {
            return payloads.removeFirst()
        }
        return nil
    }

    func nextPayload() async -> Data {
        if let payload = popPayload() {
            return payload
        }
        return await withCheckedContinuation { continuation in
            waiters.append(continuation)
        }
    }
}

private struct SubmittedCoreOp: Equatable {
    let requestID: RequestID
    let threadID: String
    let op: Op
}

private struct AppServerCoreOpCaptureError: Error, CustomStringConvertible {
    let message: String

    var description: String {
        message
    }
}

private final class AppServerCoreOpCapture: @unchecked Sendable {
    private let lock = NSLock()
    private var recordedSubmissions: [SubmittedCoreOp] = []

    var submissions: [SubmittedCoreOp] {
        lock.withLock {
            recordedSubmissions
        }
    }

    func submit(requestID: RequestID, threadID: String, op: Op) -> String {
        lock.withLock {
            recordedSubmissions.append(SubmittedCoreOp(
                requestID: requestID,
                threadID: threadID,
                op: op
            ))
        }
        switch requestID {
        case let .integer(value):
            return "turn-\(value)"
        case let .string(value):
            return "turn-\(value)"
        }
    }
}

private final class AppServerCoreOpFailingInterruptCapture: @unchecked Sendable {
    private let lock = NSLock()
    private let message: String
    private var recordedSubmissions: [SubmittedCoreOp] = []

    init(message: String) {
        self.message = message
    }

    var submissions: [SubmittedCoreOp] {
        lock.withLock {
            recordedSubmissions
        }
    }

    func submit(requestID: RequestID, threadID: String, op: Op) throws -> String {
        lock.withLock {
            recordedSubmissions.append(SubmittedCoreOp(
                requestID: requestID,
                threadID: threadID,
                op: op
            ))
        }
        if case .interrupt = op {
            throw AppServerCoreOpCaptureError(message: message)
        }
        switch requestID {
        case let .integer(value):
            return "turn-\(value)"
        case let .string(value):
            return "turn-\(value)"
        }
    }
}

