private actor LiveMultiAgentToolCapture {
    private var queued: [String: [InterAgentCommunication]] = [:]
    private var pendingWork: [String] = []
    private var runningThreadIDs: Set<String>
    private var statuses: [String: AgentStatus] = [:]
    private var lastTaskMessages: [String: String] = [:]
    private var pendingMailboxThreadIDs: Set<String> = []
    private var closed: [String] = []
    private var spawnRequests: [LiveSpawnAgentRequest] = []

    init(runningThreadIDs: Set<String> = []) {
        self.runningThreadIDs = runningThreadIDs
    }

    func queue(threadID: String, communications: [InterAgentCommunication]) {
        queued[threadID, default: []].append(contentsOf: communications)
    }

    func queuedCommunications(threadID: String) -> [InterAgentCommunication] {
        queued[threadID] ?? []
    }

    func submitPendingWork(threadID: String) {
        pendingWork.append(threadID)
    }

    func pendingWorkThreadIDs() -> [String] {
        pendingWork
    }

    func isRunning(threadID: String) -> Bool {
        runningThreadIDs.contains(threadID)
    }

    func status(threadID: String) -> AgentStatus {
        if let status = statuses[threadID] {
            return status
        }
        return runningThreadIDs.contains(threadID) ? .running : .completed(nil)
    }

    func setStatus(threadID: String, status: AgentStatus) {
        statuses[threadID] = status
        switch status {
        case .running:
            runningThreadIDs.insert(threadID)
        default:
            runningThreadIDs.remove(threadID)
        }
    }

    func recordLastTaskMessage(threadID: String, message: String) {
        lastTaskMessages[threadID] = message
    }

    func lastTaskMessage(threadID: String) -> String? {
        lastTaskMessages[threadID]
    }

    func setPendingMailbox(threadID: String) {
        pendingMailboxThreadIDs.insert(threadID)
    }

    func clearPendingMailbox(threadID: String) {
        pendingMailboxThreadIDs.remove(threadID)
    }

    func hasPendingMailbox(threadID: String) -> Bool {
        pendingMailboxThreadIDs.contains(threadID)
    }

    func waitForMailboxChange(threadID: String, timeoutMilliseconds: Int64) async -> Bool {
        if pendingMailboxThreadIDs.contains(threadID) {
            return true
        }
        if timeoutMilliseconds > 0 {
            try? await Task.sleep(nanoseconds: UInt64(timeoutMilliseconds) * 1_000_000)
        }
        return pendingMailboxThreadIDs.contains(threadID)
    }

    func close(threadIDs: [String]) {
        closed.append(contentsOf: threadIDs)
        runningThreadIDs.subtract(threadIDs)
        for threadID in threadIDs {
            statuses[threadID] = .notFound
        }
    }

    func closedThreadIDs() -> [String] {
        closed
    }

    func recordSpawnRequest(_ request: LiveSpawnAgentRequest) {
        spawnRequests.append(request)
    }

    func recordedSpawnRequests() -> [LiveSpawnAgentRequest] {
        spawnRequests
    }
}

